10	//
11	// Contributors:
12	//   ZettaScale Zenoh Team, <zenoh@zettascale.tech>
13	//
14	
15	use std::{
16	    collections::{HashMap, HashSet},
17	    fmt::{self, Debug},
18	    sync::{Arc, Weak},
19	    time::Duration,
20	};
21	
22	use async_trait::async_trait;
23	use tokio_util::sync::CancellationToken;
24	use zenoh_protocol::{
25	    core::Region,
26	    network::{
27	        declare::{self},
28	        interest::{InterestId, InterestMode, InterestOptions},
29	        Declare, DeclareBody, DeclareFinal, Interest,
30	    },
31	};
32	use zenoh_sync::get_mut_unchecked;
33	use zenoh_util::Timed;
34	
35	use super::{face::FaceState, tables::TablesLock};
36	use crate::net::routing::{
37	    dispatcher::{face::Face, tables::Tables},
38	    gateway::{register_expr_interest, NodeId, Resource},
39	    hat::{DispatcherContext, Remote, RouteCurrentDeclareResult, RouteInterestResult, SendDeclare},
40	    RoutingContext,
41	};
42	
43	#[derive(Debug, Clone)]
44	pub(crate) struct CurrentInterest {
45	    pub(crate) src: Remote,
46	    pub(crate) src_region: Region,
47	    pub(crate) src_interest_id: InterestId,
48	    pub(crate) mode: InterestMode,
49	}
50	
51	pub(crate) struct PendingCurrentInterest {
52	    pub(crate) interest: Arc<CurrentInterest>,
53	    pub(crate) cancellation_token: CancellationToken,
54	    pub(crate) rejection_token: CancellationToken,
55	}
56	
57	#[derive(Clone, PartialEq, Eq, Hash)]
58	pub(crate) struct RemoteInterest {
59	    pub(crate) res: Option<Arc<Resource>>,
60	    pub(crate) options: InterestOptions,
61	    pub(crate) mode: InterestMode,
62	}
63	
64	impl fmt::Debug for RemoteInterest {
65	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
66	        f.debug_struct("RemoteInterest")
67	            .field("res", &self.res.as_ref().map(|res| res.expr()))
68	            .field("opts", &self.options)
69	            .field("mode", &self.mode)
70	            .finish()
71	    }
72	}
73	
74	impl RemoteInterest {
75	    pub(crate) fn matches(&self, res: &Arc<Resource>) -> bool {
76	        self.res.as_ref().map(|r| r.matches(res)).unwrap_or(true)
77	    }
78	}
79	
80	pub(crate) fn finalize_pending_interests(
81	    _tables_ref: &TablesLock,
82	    face: &mut Arc<FaceState>,
83	    send_declare: &mut SendDeclare,
84	) {
85	    for (_, interest) in get_mut_unchecked(face).pending_current_interests.drain() {
86	        finalize_pending_interest(interest, send_declare);
87	    }
88	}
89	
90	pub(crate) fn finalize_pending_interest(
91	    pending_interest: PendingCurrentInterest,
92	    send_declare: &mut SendDeclare,
93	) {
94	    let interest = pending_interest.interest;
95	    pending_interest.cancellation_token.cancel();
96	    if let Some(interest) = Arc::into_inner(interest) {
97	        // FIXME(regions): this is only safe as long as router interests remain unimplemented
98	        let src_face = interest
99	            .src
100	            .downcast_ref_to_face()
101	            .expect("interest source remote should be a face");
102	
103	        tracing::debug!(
104	            "{}:{} Propagate DeclareFinal",
105	            src_face,
106	            interest.src_interest_id
107	        );
108	
109	        send_declare(
110	            &src_face.primitives,
111	            RoutingContext::new(Declare {
112	                interest_id: Some(interest.src_interest_id),
113	                ext_qos: declare::ext::QoSType::DECLARE,
114	                ext_tstamp: None,
115	                ext_nodeid: declare::ext::NodeIdType::DEFAULT,
116	                body: DeclareBody::DeclareFinal(DeclareFinal),
117	            }),
118	        );
119	    }
120	}
121	
122	#[derive(Clone)]
123	pub(crate) struct CurrentInterestCleanup {
124	    tables: Arc<TablesLock>,
125	    face: Weak<FaceState>,
126	    id: InterestId,
127	    interests_timeout: Duration,
128	}
129	
130	impl CurrentInterestCleanup {
131	    pub(crate) fn spawn_interest_clean_up_task(
132	        face: &Arc<FaceState>,
133	        tables_ref: &Arc<TablesLock>,
134	        id: u32,
135	        interests_timeout: Duration,
136	    ) {
137	        let mut cleanup = CurrentInterestCleanup {
138	            tables: tables_ref.clone(),
139	            face: Arc::downgrade(face),
140	            id,
141	            interests_timeout,
142	        };
143	        if let Some(pending_interest) = face.pending_current_interests.get(&id) {
144	            let cancellation_token = pending_interest.cancellation_token.clone();
145	            let rejection_token = pending_interest.rejection_token.clone();
146	            face.task_controller
147	                .spawn_with_rt(zenoh_runtime::ZRuntime::Net, async move {
148	                    tokio::select! {
149	                        _ = tokio::time::sleep(cleanup.interests_timeout) => { cleanup.run().await }
150	                        _ = cancellation_token.cancelled() => {}
151	                        _ = rejection_token.cancelled() => { cleanup.execute(false).await }
152	                    }
153	                });
154	        }
155	    }
156	
157	    async fn execute(&mut self, print_warning: bool) {
158	        if let Some(mut face) = self.face.upgrade() {
159	            let ctrl_lock = zlock!(self.tables.ctrl_lock);
160	            if let Some(interest) = get_mut_unchecked(&mut face)
161	                .pending_current_interests
162	                .remove(&self.id)
163	            {
164	                drop(ctrl_lock);
165	                if print_warning {
166	                    tracing::warn!(
167	                        "{}:{} Didn't receive DeclareFinal for interest {:?}:{}: Timeout({:#?})!",
168	                        face,
169	                        self.id,
170	                        interest.interest.src.downcast_ref_to_face(),
171	                        interest.interest.src_interest_id,
172	                        self.interests_timeout,
173	                    );
174	                }
175	                finalize_pending_interest(interest, &mut |p, m| {
176	                    m.with_mut(|m| {
177	                        p.send_declare(m);
178	                    })
179	                });
180	            }
181	        }
182	    }
183	}
184	
185	#[async_trait]
186	impl Timed for CurrentInterestCleanup {
187	    async fn run(&mut self) {
188	        self.execute(true).await;
189	    }
190	}
191	
192	impl Face {
193	    #[tracing::instrument(
194	        level = "debug", 
195	        skip(self, msg, send_declare),
196	        fields(
197	            id = msg.id,
198	            mode = ?msg.mode,
199	            opts = %msg.options,
200	            expr = msg.wire_expr.as_ref().map(|we| we.to_string())
201	        ),
202	        ret
203	    )]
204	    pub(crate) fn interest(&self, msg: &mut Interest, send_declare: &mut SendDeclare) {
205	        let region = self.state.region;
206	
207	        if region.bound().is_north() && !self.state.whatami.is_peer() {
208	            tracing::error!(
209	                src = %self.state,
210	                "Ignoring interest from non-peer north-bound face (illegal)"
211	            );
212	            return;
213	        }
214	
215	        if self.state.whatami.is_router() {
216	            tracing::warn!("Ignoring interest from router (unsupported)");
217	            return;
218	        }
219	
220	        if msg.options.aggregate() && self.state.whatami.is_peer() {
221	            tracing::warn!("Ignoring aggregate interest option from peer (unsupported)");
222	            msg.options -= InterestOptions::AGGREGATE;
223	        }
224	
225	        if msg.options.aggregate() && msg.options.tokens() {
226	            tracing::error!("Ignoring aggregate interest option for tokens (illegal)");
227	            msg.options -= InterestOptions::AGGREGATE;
228	        }
229	
230	        if msg.mode == InterestMode::Current
231	            && (msg.options.subscribers() || msg.options.queryables() || !msg.options.tokens())
232	        {
233	            tracing::error!("Current interests may only refer to tokens (illegal)");
234	            return;
235	        }
236	
237	        let msg = &*msg;
238	
239	        let Interest {
240	            id,
241	            mode,
242	            options,
243	            wire_expr,
244	            ..
245	        } = msg;
246	
247	        if options.keyexprs() && mode != &InterestMode::Current {
248	            register_expr_interest(
249	                &self.tables,
250	                &mut self.state.clone(),
251	                *id,
252	                wire_expr.as_ref(),
253	            );
254	        }
255	
256	        self.with_mapped_optional_expr(wire_expr.as_ref(), |tables, res| {
257	            let hats = &mut tables.hats;
258	
259	            let mut ctx = DispatcherContext {
260	                tables_lock: &self.tables,
261	                tables: &mut tables.data,
262	                src_face: &mut self.state.clone(),
263	                send_declare,
264	            };
265	
266	            let Some(src) = hats[region].new_remote(ctx.src_face, msg.ext_nodeid.node_id) else {
267	                return;
268	            };
269	
270	            let route_interest_res =
271	                hats[Region::North].route_interest(ctx.reborrow(), msg, res.clone(), &src);
272	
273	            if msg.mode.is_current() {
274	                if msg.options.subscribers() {
275	                    let other_sub_matches = hats
276	                        .values()
277	                        .filter(|hat| hat.region() != region)
278	                        .flat_map(|hat| {
279	                            hat.remote_subscribers_matching(ctx.tables, res.as_deref())
280	                                .into_iter()
281	                        })
282	                        .collect::<HashMap<_, _>>();
283	
284	                    hats[region].send_current_subscribers(
285	                        ctx.reborrow(),
286	                        msg,
287	                        res.clone(),
288	                        other_sub_matches,
289	                    );
290	                }
291	
292	                if msg.options.queryables() {
293	                    let other_qabl_matches = hats
294	                        .values()
295	                        .filter(|hat| hat.region() != region)
296	                        .flat_map(|hat| {
297	                            hat.remote_queryables_matching(ctx.tables, res.as_deref())
298	                                .into_iter()
299	                        })
300	                        .collect::<HashMap<_, _>>();
301	                    hats[region].send_current_queryables(
302	                        ctx.reborrow(),
303	                        msg,
304	                        res.clone(),
305	                        other_qabl_matches,
306	                    );
307	                }
308	
309	                if msg.options.tokens() {
310	                    let other_token_matches = hats
311	                        .values()
312	                        .filter(|hat| hat.region() != region)
313	                        .flat_map(|hat| {
314	                            hat.remote_tokens_matching(ctx.tables, res.as_deref())
315	                                .into_iter()
316	                        })
317	                        .collect::<HashSet<_>>();
318	                    hats[region].send_current_tokens(
319	                        ctx.reborrow(),
320	                        msg,
321	                        res.clone(),
322	                        other_token_matches,
323	                    );
324	                }
325	            }
326	
327	            if msg.mode.is_future() {
328	                hats[region].register_interest(ctx.reborrow(), msg, res);
329	            }
330	
331	            if let RouteInterestResult::ResolvedCurrentInterest = route_interest_res {
332	                hats[region].send_declare_final(ctx.reborrow(), msg.id, &src);
333	            }
334	        });
335	    }
336	
337	    #[tracing::instrument(
338	        level = "debug",
339	        name = "interest",
340	        skip(self, msg),
341	        fields(
342	            id = msg.id,
343	            mode = ?InterestMode::Final,
344	            opts = %msg.options,
345	            expr = msg.wire_expr.as_ref().map(|we| we.to_string())
346	        ),
347	        ret
348	    )]
349	    pub(crate) fn interest_final(&self, msg: &Interest) {
350	        let mut wtables = zwrite!(self.tables.tables);
351	        let tables = &mut *wtables;
352	
353	        let mut ctx = DispatcherContext {
354	            tables_lock: &self.tables,
355	            tables: &mut tables.data,
356	            src_face: &mut self.state.clone(),
357	            send_declare: &mut |_, _| unreachable!(),
358	        };
359	
360	        // Unregister keyexpr interest
361	        get_mut_unchecked(ctx.src_face)
362	            .remote_key_interests
363	            .remove(&msg.id);
364	
365	        let hats = &mut tables.hats;
366	        let region = ctx.src_face.region;
367	
368	        let Some(remote_interest) = hats[region].unregister_interest(ctx.reborrow(), msg) else {
369	            return;
370	        };
371	
372	        hats[Region::North].route_interest_final(ctx, msg, &remote_interest);
373	    }
374	
375	    #[tracing::instrument(level = "debug", skip(self, wtables, _node_id, send_declare), ret)]
376	    pub(crate) fn declare_final(
377	        &self,
378	        wtables: &mut Tables,
379	        interest_id: InterestId,
380	        _node_id: NodeId,
381	        send_declare: &mut SendDeclare,
382	    ) {
383	        let tables = &mut *wtables;
384	
385	        let mut ctx = DispatcherContext {
386	            tables_lock: &self.tables,
387	            tables: &mut tables.data,
388	            src_face: &mut self.state.clone(),
389	            send_declare,
390	        };
391	
392	        let hats = &mut tables.hats;
393	        let region = ctx.src_face.region;
394	
395	        if region.bound().is_south() {
396	            tracing::error!("Received DeclareFinal from south-bound face");
397	            return;
398	        }
399	
400	        // TODO(regions): this is too conservative, the north hat should be able to decide what
401	        // keyexpr(s)—if not all—are affected and whether this finalization concerns subscribers
402	        // or queryables or borth.
403	        hats[region].disable_all_routes(ctx.tables);
404	
405	        match hats[region].route_declare_final(ctx.reborrow(), interest_id) {
406	            RouteCurrentDeclareResult::Noop | RouteCurrentDeclareResult::NoBreadcrumb => {} // ¯\_(ツ)_/¯
407	            RouteCurrentDeclareResult::Breadcrumb { interest } => {
408	                debug_assert!(interest.mode.is_current());
409	
410	                hats[interest.src_region].send_declare_final(
411	                    ctx,
412	                    interest.src_interest_id,
413	                    &interest.src,
414	                );
415	            }
416	        }
417	    }
418	}
419

