60	
61	            let mut ctx = DispatcherContext {
62	                tables_lock: &self.tables,
63	                tables: &mut tables.data,
64	                src_face: &mut self.state.clone(),
65	                send_declare,
66	            };
67	
68	            hats[region].register_subscriber(ctx.reborrow(), id, res.clone(), node_id, sub_info);
69	
70	            hats[region].disable_data_routes(&mut res);
71	
72	            for dst in hats.regions().collect_vec() {
73	                let other_info = hats
74	                    .values()
75	                    .filter(|hat| hat.region() != dst)
76	                    .flat_map(|hat| hat.remote_subscribers_of(ctx.tables, &res))
77	                    .reduce(|_, _| SubscriberInfo);
78	
79	                hats[dst].propagate_subscriber(ctx.reborrow(), res.clone(), other_info);
80	            }
81	        });
82	    }
