85	        level = "debug",
86	        skip(self, send_declare),
87	        fields(expr = %expr, node_id = node_id_as_source(node_id)),
88	        ret
89	    )]
90	    pub(crate) fn undeclare_subscriber(
91	        &self,
92	        id: SubscriberId,
93	        expr: &WireExpr,
94	        node_id: NodeId,
95	        send_declare: &mut SendDeclare,
96	    ) {
97	        self.with_mapped_nullable_expr(expr, /* make_if_unknown */ false, |tables, res| {
98	            let region = self.state.region;
99	
100	            let mut ctx = DispatcherContext {
101	                tables_lock: &self.tables,
102	                tables: &mut tables.data,
103	                src_face: &mut self.state.clone(),
104	                send_declare,
105	            };
106	
107	            if let Some(mut res) =
108	                tables.hats[region].unregister_subscriber(ctx.reborrow(), id, res.clone(), node_id)
109	            {
110	                tables.hats[region].disable_data_routes(&mut res);
111	
112	                let mut remaining = tables
113	                    .hats
114	                    .values_mut()
115	                    .filter(|hat| hat.remote_subscribers_of(ctx.tables, &res).is_some())
116	                    .collect_vec();
117	
118	                if (*remaining).is_empty() {
119	                    for hat in tables.hats.values_mut() {
120	                        hat.unpropagate_subscriber(ctx.reborrow(), res.clone());
121	                    }
122	                    Resource::clean(&mut res);
123	                } else if let [last_owner] = &mut *remaining {
124	                    last_owner.unpropagate_last_non_owned_subscriber(ctx, res.clone())
125	                }
126	            }
127	        });
128	    }
129	}
130	
131	macro_rules! treat_timestamp {
132	    ($hlc:expr, $payload:expr, $drop:expr) => {
133	        // if an HLC was configured (via Config.add_timestamp),
134	        // check DataInfo and add a timestamp if there isn't
135	        if let Some(hlc) = $hlc {
136	            if let zenoh_protocol::zenoh::PushBody::Put(data) = &mut $payload {
137	                if let Some(ref ts) = data.timestamp {
138	                    // Timestamp is present; update HLC with it (possibly raising error if delta exceed)
139	                    match hlc.update_with_timestamp(ts) {
140	                        Ok(()) => (),
141	                        Err(e) => {
142	                            if $drop {
143	                                tracing::error!(
144	                                    "Error treating timestamp for received Data ({}). Drop it!",
145	                                    e
146	                                );
147	                                return;
148	                            } else {
149	                                data.timestamp = Some(hlc.new_timestamp());
150	                                tracing::error!(
151	                                    "Error treating timestamp for received Data ({}). Replace timestamp: {:?}",
152	                                    e,
153	                                    data.timestamp);
154	                            }
155	                        }
156	                    }
157	                } else {
158	                    // Timestamp not present; add one
159	                    data.timestamp = Some(hlc.new_timestamp());
160	                    tracing::trace!("Adding timestamp to DataInfo: {:?}", data.timestamp);
161	                }
162	            }
163	        }
164	    }
165	}
166	
167	#[inline]
168	fn get_hat_data_route(
169	    tables: &Tables,
170	    src_face: &FaceState,
171	    expr: &RoutingExpr,
172	    node_id: NodeId,
173	    region: &Region,
174	) -> Arc<Route> {
175	    let node_id = tables.hats[region].map_routing_context(&tables.data, src_face, node_id);
176	    let compute_route =
177	        || tables.hats[region].compute_data_route(&tables.data, &src_face.region, expr, node_id);
178	    match expr
179	        .resource()
180	        .as_ref()
181	        .and_then(|res| res.ctx.as_ref())
182	        .map(|ctx| &ctx.hats[region].data_routes)
183	    {
184	        Some(data_routes) => get_or_set_route(
185	            data_routes,
186	            tables.data.hats[region].routes_version,
