215	/// Global version number for route computation.
216	/// Use 64bit to not care about rollover.
217	pub type RoutesVersion = u64;
218	
219	/// Per-hat data/query routes.
220	///
221	/// 1. Routes depend on the source region of a message.
222	///
223	///   + For instance, a north peer hat N may route a message in its region only if said message
224	///     arrives from a south-bound face, otherwise N would not route messages within its region.
225	///     Thus routes depend on the source bound of a message.
226	///
227	///   + Given two south peer sub-regions, say S1 and S2, S1 may route a message to peers in its
228	///     region only said the message originates in S2 and vice-versa. Thus routes not only depend
229	///     on the source bound of a message but on its source region more generally.
230	///
231	/// 2. Routes depend on the source node id for router hats. In a `R1 - R - R2` topology, R would
232	///    route a message to R1 only if it originates in R2 and vice-versa.
233	pub(crate) struct Routes<T> {
234	    /// Mapping from **source** [`Region`] and [`NodeId`] to data/query routes.
235	    mapping: RegionMap<NodeIdMap<T>>,
236	    version: u64,
237	}
238	
239	pub(crate) type NodeIdMap<T> = Vec<Option<T>>;
240	
241	impl<T> Default for Routes<T> {
242	    fn default() -> Self {
243	        Self {
244	            mapping: RegionMap::default(),
245	            version: 0,
246	        }
247	    }
248	}
249	
250	impl<T> Routes<T> {
251	    pub(crate) fn clear(&mut self) {
252	        self.mapping.clear();
253	    }
254	
255	    #[inline]
256	    pub(crate) fn get_route(
257	        &self,
258	        version: RoutesVersion,
259	        region: &Region,
260	        node_id: NodeId,
261	    ) -> Option<&T> {
262	        if version != self.version {
263	            return None;
264	        }
265	
266	        self.mapping
267	            .get(region)
268	            .and_then(|rs| rs.get(node_id as usize))
269	            .and_then(|r| r.as_ref())
270	    }
271	
272	    #[inline]
273	    pub(crate) fn set_route(
274	        &mut self,
275	        version: RoutesVersion,
276	        region: &Region,
277	        node_id: NodeId,
278	        route: T,
279	    ) {
280	        if self.version != version {
281	            self.clear();
282	            self.version = version;
283	        }
284	
285	        let aux = |routes: &mut NodeIdMap<T>| {
286	            routes.resize_with(node_id as usize + 1, || None);
287	            routes[node_id as usize] = Some(route);
288	        };
289	
290	        if let Some(routes) = self.mapping.get_mut(region) {
291	            aux(routes);
292	        } else {
293	            let mut routes = NodeIdMap::default();
294	            aux(&mut routes);
295	            self.mapping.insert(*region, routes);
296	        }
297	    }
298	}
299	
300	pub(crate) fn get_or_set_route<T: Clone>(
301	    routes: &RwLock<Routes<T>>,
302	    version: RoutesVersion,
303	    region: &Region,
304	    node_id: NodeId,
305	    compute_route: impl FnOnce() -> T,
306	) -> T {
307	    if let Some(route) = routes.read().unwrap().get_route(version, region, node_id) {
308	        return route.clone();
309	    }
310	    let mut routes = routes.write().unwrap();
311	    // NOTE(regions): we supposedly re-read the routes here because they might've changed, but I'm
312	    // not sure this is true given that all callers would've acquired `TablesLock::tables`.
313	    if let Some(route) = routes.get_route(version, region, node_id) {
314	        return route.clone();
315	    }
316	    let route = compute_route();
317	    routes.set_route(version, region, node_id, route.clone());
318	    route
319	}
