534	    #[tracing::instrument(level = "trace")]
535	    pub fn clean(res: &mut Arc<Resource>) {
536	        let mut resclone = res.clone();
537	        let mutres = get_mut_unchecked(&mut resclone);
538	        if let Some(ref mut parent) = mutres.parent {
539	            tracing::trace!(strong_count = Arc::strong_count(res));
540	            if Arc::strong_count(res) <= 3 && res.children.is_empty() {
541	                // consider only childless resource held by only one external object (+ 1 strong count for resclone, + 1 strong count for res.parent to a total of 3 )
542	                tracing::debug!("Unregister resource {}", res.expr());
543	                if let Some(context) = mutres.ctx.as_mut() {
544	                    for match_ in &mut context.matches {
545	                        let mut match_ = match_.upgrade().unwrap();
546	                        if !Arc::ptr_eq(&match_, res) {
547	                            let mutmatch = get_mut_unchecked(&mut match_);
548	                            if let Some(ctx) = mutmatch.ctx.as_mut() {
549	                                ctx.matches
550	                                    .retain(|x| !Arc::ptr_eq(&x.upgrade().unwrap(), res));
551	                            }
552	                        }
553	                    }
554	                }
555	                mutres.nonwild_prefix.take();
556	                {
557	                    get_mut_unchecked(parent).children.remove(res.suffix());
558	                }
559	                Resource::clean(parent);
560	            }
561	        }
562	    }
