585	    #[tracing::instrument(level = "debug", skip(tables), ret)]
586	    pub fn make_resource(
587	        tables: &mut Tables,
588	        from: &mut Arc<Resource>,
589	        mut suffix: &str,
590	    ) -> Arc<Resource> {
591	        if !suffix.is_empty() && !suffix.starts_with('/') {
592	            if let Some(parent) = &mut from.parent.clone() {
593	                return Resource::make_resource(tables, parent, &[from.suffix(), suffix].concat());
594	            }
595	        }
596	        let mut from = from.clone();
597	        // do not use recursion as the tree may have arbitrary depth
598	        while let Some((chunk, rest)) = Self::split_first_chunk(suffix) {
599	            if let Some(child) = get_mut_unchecked(&mut from).children.get(chunk) {
600	                from = child.0.clone();
601	            } else {
602	                let new = Arc::new(Resource::new(&from, chunk, None));
603	                if rest.is_empty() {
604	                    tracing::debug!("Register resource {}", new.expr());
605	                }
606	                get_mut_unchecked(&mut from)
607	                    .children
608	                    .insert(Child(new.clone()));
609	                from = new;
610	            };
611	            suffix = rest;
612	        }
613	        let hat = tables
614	            .hats
615	            .map_ref(|d| HatResourceContext::new(d.new_resource()));
616	        Resource::upgrade_resource(&mut from, hat);
617	        from
618	    }
