620	    #[inline]
621	    pub fn get_resource_ref<'a>(
622	        mut from: &'a Arc<Resource>,
623	        mut suffix: &str,
624	    ) -> Option<&'a Arc<Resource>> {
625	        if !suffix.is_empty() && !suffix.starts_with('/') {
626	            if let Some(parent) = &from.parent {
627	                return Resource::get_resource_ref(parent, &[from.suffix(), suffix].concat());
628	            }
629	        }
630	        // do not use recursion as the tree may have arbitrary depth
631	        while let Some((chunk, rest)) = Self::split_first_chunk(suffix) {
632	            (from, suffix) = (from.children.get(chunk)?, rest);
633	        }
634	        Some(from)
