642	    /// Split the suffix at the next '/' (after leading one), returning None if the suffix is empty.
643	    ///
644	    /// Suffix usually starts with '/', so this first slash is kept as part of the split chunk.
645	    /// The rest will contain the slash of the split.
646	    /// For example `split_first_chunk("/a/b") == Some(("/a", "/b"))`.
647	    #[inline(always)]
648	    fn split_first_chunk(suffix: &str) -> Option<(&str, &str)> {
649	        if suffix.is_empty() {
650	            return None;
651	        }
652	        // don't count the first char which may be a leading slash to find the next one
653	        Some(match suffix[1..].find('/') {
654	            // don't forget to add 1 to the index because of `[1..]` slice above
655	            Some(idx) => suffix.split_at(idx + 1),
656	            None => (suffix, ""),
657	        })
658	    }
