660	    #[inline]
661	    pub fn decl_key(res: &Arc<Resource>, face: &mut Arc<FaceState>) -> WireExpr<'static> {
662	        if face.is_local {
663	            return res.expr().to_string().into();
664	        }
665	
666	        let (nonwild_prefix, wildsuffix) = Resource::nonwild_prefix(res);
667	        match nonwild_prefix {
668	            Some(mut nonwild_prefix) => {
669	                if let Some(ctx) = get_mut_unchecked(&mut nonwild_prefix)
670	                    .face_ctxs
671	                    .get(&face.id)
672	                {
673	                    if let Some(expr_id) = ctx.remote_expr_id {
674	                        return WireExpr {
675	                            scope: expr_id,
676	                            suffix: wildsuffix.into(),
677	                            mapping: Mapping::Receiver,
678	                        };
679	                    }
680	                    if let Some(expr_id) = ctx.local_expr_id {
681	                        return WireExpr {
682	                            scope: expr_id,
683	                            suffix: wildsuffix.into(),
684	                            mapping: Mapping::Sender,
685	                        };
686	                    }
687	                }
688	                if face.region.bound().is_north()
689	                    || face.remote_key_interests.values().any(|res| {
690	                        res.as_ref()
691	                            .map(|res| res.matches(&nonwild_prefix))
692	                            .unwrap_or(true)
693	                    })
694	                {
695	                    let ctx = get_mut_unchecked(&mut nonwild_prefix)
696	                        .face_ctxs
697	                        .entry(face.id)
698	                        .or_insert_with(|| Arc::new(FaceContext::new(face.clone())));
699	                    let expr_id = face.get_next_local_id();
700	                    get_mut_unchecked(ctx).local_expr_id = Some(expr_id);
701	                    get_mut_unchecked(face)
702	                        .local_mappings
703	                        .insert(expr_id, nonwild_prefix.clone());
704	                    face.primitives.send_declare(RoutingContext::with_expr(
705	                        &mut Declare {
706	                            interest_id: None,
707	                            ext_qos: declare::ext::QoSType::DECLARE,
708	                            ext_tstamp: None,
709	                            ext_nodeid: declare::ext::NodeIdType::DEFAULT,
710	                            body: DeclareBody::DeclareKeyExpr(DeclareKeyExpr {
711	                                id: expr_id,
712	                                wire_expr: nonwild_prefix.expr().to_string().into(),
713	                            }),
714	                        },
715	                        nonwild_prefix.expr().to_string(),
716	                    ));
717	                    face.update_interceptors_caches(&mut nonwild_prefix);
718	                    WireExpr {
719	                        scope: expr_id,
720	                        suffix: wildsuffix.into(),
721	                        mapping: Mapping::Sender,
722	                    }
723	                } else {
724	                    res.expr().to_string().into()
725	                }
726	            }
727	            None => wildsuffix.into(),
728	        }
729	    }
730	
731	    /// Return the best locally/remotely declared keyexpr, i.e. with the smallest suffix, matching
732	    /// the given suffix and session id.
733	    ///
734	    /// The goal is to save bandwidth by using the shortest keyexpr on the wire. It works by
735	    /// recursively walk through the children tree, looking for an already declared keyexpr for the
736	    /// session.
737	    /// If none is found, and if the tested resource itself doesn't have a declared keyexpr,
738	    /// then the parent tree is walked through. If there is still no declared keyexpr, the whole
739	    /// prefix+suffix string is used.
740	    pub fn get_best_key<'a>(&self, suffix: &'a str, sid: usize) -> WireExpr<'a> {
741	        /// Retrieve a declared keyexpr, either local or remote.
742	        fn get_wire_expr<'a>(
743	            prefix: &Resource,
744	            suffix: impl FnOnce() -> Cow<'a, str>,
745	            sid: usize,
746	        ) -> Option<WireExpr<'a>> {
747	            let ctx = prefix.face_ctxs.get(&sid)?;
748	            let (scope, mapping) = match (ctx.remote_expr_id, ctx.local_expr_id) {
749	                (Some(expr_id), _) => (expr_id, Mapping::Receiver),
750	                (_, Some(expr_id)) => (expr_id, Mapping::Sender),
751	                _ => return None,
752	            };
753	            Some(WireExpr {
754	                scope,
755	                suffix: suffix(),
756	                mapping,
757	            })
758	        }
759	        /// Walk through the children tree, looking for a declared keyexpr.
760	        fn get_best_child_key<'a>(
761	            mut prefix: &Resource,
762	            suffix: &'a str,
763	            sid: usize,
764	        ) -> Option<WireExpr<'a>> {
765	            let mut suffix_rest = suffix;
766	            // do not use recursion as the tree may have arbitrary depth
767	            // first we get the closest matching child
768	            while let Some((chunk, rest)) = Resource::split_first_chunk(suffix_rest) {
769	                match prefix.children.get(chunk) {
770	                    Some(child) => prefix = child,
771	                    None => break,
772	                }
773	                suffix_rest = rest;
774	            }
775	            // then we go backward checking the child and its parents
776	            while suffix_rest != suffix {
777	                if let Some(wire_expr) = get_wire_expr(prefix, || suffix_rest.into(), sid) {
778	                    return Some(wire_expr);
779	                }
780	                suffix_rest = &suffix[suffix.len() - suffix_rest.len() - prefix.suffix().len()..];
781	                prefix = prefix.parent.as_ref().unwrap();
782	            }
783	            None
784	        }
785	        /// Walk through the parent tree, looking for a declared keyexpr.
786	        fn get_best_parent_key<'a>(
787	            prefix: &Resource,
788	            suffix: &'a str,
789	            sid: usize,
790	            mut parent: &Resource,
791	        ) -> Option<WireExpr<'a>> {
792	            // do not use recursion as the tree may have arbitrary depth
793	            loop {
794	                let parent_suffix = || [&prefix.expr[parent.expr.len()..], suffix].concat().into();
795	                if let Some(wire_expr) = get_wire_expr(parent, parent_suffix, sid) {
796	                    return Some(wire_expr);
797	                }
798	                match parent.parent.as_ref() {
799	                    Some(p) => parent = p,
800	                    None => return None,
801	                }
802	            }
803	        }
804	        get_best_child_key(self, suffix, sid)
805	            .or_else(|| get_wire_expr(self, || suffix.into(), sid))
806	            .or_else(|| get_best_parent_key(self, suffix, sid, self.parent.as_ref()?))
807	            .unwrap_or_else(|| [&self.expr, suffix].concat().into())
808	    }
