810	    pub fn get_matches(tables: &TablesData, key_expr: &keyexpr) -> Vec<Weak<Resource>> {
811	        pub fn visit_nodes<T>(node: T, mut visit: impl FnMut(T, &mut VecDeque<T>)) {
812	            let mut nodes = VecDeque::from([node]);
813	            while let Some(node) = nodes.pop_front() {
814	                visit(node, &mut nodes);
815	            }
816	        }
817	        fn get_matches_from(
818	            key_expr: &keyexpr,
819	            from: &Arc<Resource>,
820	            matches: &mut Vec<Weak<Resource>>,
821	        ) {
822	            visit_nodes((key_expr, from), |(key_expr, from), nodes| {
823	                if from.parent.is_none() || from.suffix() == "/" {
824	                    for child in from.children.iter() {
825	                        nodes.push_back((key_expr, child));
826	                    }
827	                    return;
828	                }
829	                let suffix: &keyexpr = from
830	                    .suffix()
831	                    .strip_prefix('/')
832	                    .unwrap_or(from.suffix())
833	                    .try_into()
834	                    .unwrap();
835	                let (ke_chunk, ke_rest) = match key_expr.split_once('/') {
836	                    // SAFETY: chunks of keyexpr are valid keyexprs
837	                    Some((chunk, rest)) => unsafe {
838	                        (
839	                            keyexpr::from_str_unchecked(chunk),
840	                            Some(keyexpr::from_str_unchecked(rest)),
841	                        )
842	                    },
843	                    None => (key_expr, None),
844	                };
845	                let ke_chunk_intersects_suffix = ke_chunk.intersects(suffix);
846	                let ke_chunk_is_wild = ke_chunk.as_bytes() == b"**";
847	                let suffix_is_wild = suffix.as_bytes() == b"**";
848	                match ke_rest {
849	                    None => {
850	                        if ke_chunk_intersects_suffix {
851	                            if from.ctx.is_some() {
852	                                matches.push(Arc::downgrade(from));
853	                            }
854	                            if let Some(child) =
855	                                from.children.get("/**").or_else(|| from.children.get("**"))
856	                            {
857	                                if child.ctx.is_some() {
858	                                    matches.push(Arc::downgrade(child))
859	                                }
860	                            }
861	                        }
862	                        if (ke_chunk_is_wild && ke_chunk_intersects_suffix) || suffix_is_wild {
863	                            for child in from.children.iter() {
864	                                nodes.push_back((key_expr, child));
865	                            }
866	                        }
867	                    }
868	                    Some(rest) => {
869	                        if ke_chunk_intersects_suffix
870	                            && rest.as_bytes() == b"**"
871	                            && from.ctx.is_some()
872	                        {
873	                            matches.push(Arc::downgrade(from));
874	                        }
875	                        for child in from.children.iter() {
876	                            if (ke_chunk_is_wild && ke_chunk_intersects_suffix) || suffix_is_wild {
877	                                nodes.push_back((key_expr, child));
878	                            } else if ke_chunk_intersects_suffix {
879	                                nodes.push_back((rest, child));
880	                            }
881	                        }
882	                        if (suffix_is_wild && ke_chunk_intersects_suffix) || ke_chunk_is_wild {
883	                            nodes.push_back((rest, from));
884	                        }
885	                    }
886	                };
887	            })
888	        }
889	        let mut matches = Vec::new();
890	        get_matches_from(key_expr, &tables.root_res, &mut matches);
891	        matches.sort_unstable_by_key(Weak::as_ptr);
892	        matches.dedup_by_key(|res| Weak::as_ptr(res));
893	        matches
894	    }
895	
896	    pub fn match_resource(
897	        _tables: &TablesData,
898	        res: &mut Arc<Resource>,
899	        matches: Vec<Weak<Resource>>,
900	    ) {
901	        if res.ctx.is_some() {
902	            for match_ in &matches {
903	                let mut match_ = match_.upgrade().unwrap();
904	                get_mut_unchecked(&mut match_)
905	                    .context_mut()
906	                    .matches
907	                    .push(Arc::downgrade(res));
908	            }
909	            get_mut_unchecked(res).context_mut().matches = matches;
910	        } else {
911	            tracing::error!("Call match_resource() on context less res {}", res.expr());
912	        }
913	    }
914	
915	    pub fn upgrade_resource(res: &mut Arc<Resource>, hat: RegionMap<HatResourceContext>) {
916	        if res.ctx.is_none() {
917	            get_mut_unchecked(res).ctx = Some(Box::new(ResourceContext::new(hat)));
918	        }
919	    }
