921	    pub(crate) fn get_ingress_cache(
922	        &self,
923	        face: &Face,
924	        interceptor: &InterceptorsChain,
925	    ) -> Option<InterceptorCacheValueType> {
926	        self.face_ctxs
927	            .get(&face.state.id)
928	            .and_then(|ctx| ctx.in_interceptor_cache.value(interceptor, self))
929	    }
930	
931	    pub(crate) fn get_egress_cache(
932	        &self,
933	        face: &Face,
934	        interceptor: &InterceptorsChain,
935	    ) -> Option<InterceptorCacheValueType> {
936	        self.face_ctxs
937	            .get(&face.state.id)
938	            .and_then(|ctx| ctx.e_interceptor_cache.value(interceptor, self))
939	    }
940	}
