942	pub(crate) fn register_expr(
943	    tables: &TablesLock,
944	    face: &mut Arc<FaceState>,
945	    expr_id: ExprId,
946	    expr: &WireExpr,
947	) {
948	    let rtables = zread!(tables.tables);
949	    match rtables
950	        .data
951	        .get_mapping(face, &expr.scope, expr.mapping)
952	        .cloned()
953	    {
954	        Some(mut prefix) => match face.remote_mappings.get(&expr_id) {
955	            Some(res) => {
956	                let mut fullexpr = prefix.expr().to_string();
957	                fullexpr.push_str(expr.suffix.as_ref());
958	                if res.expr() != fullexpr {
959	                    tracing::error!(
960	                        "{} Resource {} remapped. Remapping unsupported!",
961	                        face,
962	                        expr_id
963	                    );
964	                }
965	            }
966	            None => {
967	                let res = Resource::get_resource(&prefix, &expr.suffix);
968	                let (mut res, mut wtables) = if res
969	                    .as_ref()
970	                    .map(|r| r.ctx.is_some())
971	                    .unwrap_or(false)
972	                {
973	                    drop(rtables);
974	                    let wtables = zwrite!(tables.tables);
975	                    (res.unwrap(), wtables)
976	                } else {
977	                    let mut fullexpr = prefix.expr().to_string();
978	                    fullexpr.push_str(expr.suffix.as_ref());
979	                    let mut matches = keyexpr::new(fullexpr.as_str())
980	                        .map(|ke| Resource::get_matches(&rtables.data, ke))
981	                        .unwrap_or_default();
982	                    drop(rtables);
983	                    let mut wtables = zwrite!(tables.tables);
984	                    let mut res =
985	                        Resource::make_resource(&mut wtables, &mut prefix, expr.suffix.as_ref());
986	                    matches.push(Arc::downgrade(&res));
987	                    Resource::match_resource(&wtables.data, &mut res, matches);
988	                    (res, wtables)
989	                };
990	                let ctx = get_mut_unchecked(&mut res)
991	                    .face_ctxs
992	                    .entry(face.id)
993	                    .or_insert_with(|| Arc::new(FaceContext::new(face.clone())));
994	
995	                get_mut_unchecked(ctx).remote_expr_id = Some(expr_id);
996	
997	                get_mut_unchecked(face)
998	                    .remote_mappings
999	                    .insert(expr_id, res.clone());
1000	
1001	                let tables = &mut *wtables;
1002	                let hats = &mut tables.hats;
1003	                let region = face.region;
1004	
1005	                hats[region].disable_data_routes(&mut res);
1006	                hats[region].disable_query_routes(&mut res);
1007	
1008	                face.update_interceptors_caches(&mut res);
1009	                drop(wtables);
1010	            }
1011	        },
1012	        None => tracing::error!(
1013	            "{} Declare resource with unknown scope {}!",
1014	            face,
1015	            expr.scope
1016	        ),
1017	    }
1018	}
1019	
1020	pub(crate) fn unregister_expr(tables: &TablesLock, face: &mut Arc<FaceState>, expr_id: ExprId) {
1021	    let mut wtables = zwrite!(tables.tables);
1022	
1023	    let tables = &mut *wtables;
1024	    let hats = &mut tables.hats;
1025	    let region = face.region;
1026	
1027	    match get_mut_unchecked(face).remote_mappings.remove(&expr_id) {
1028	        Some(mut res) => {
1029	            if let Some(ctx) = get_mut_unchecked(&mut res).face_ctxs.get_mut(&face.id) {
1030	                get_mut_unchecked(ctx).remote_expr_id = None;
1031	            }
1032	            hats[region].disable_data_routes(&mut res);
1033	            hats[region].disable_query_routes(&mut res);
1034	            face.update_interceptors_caches(&mut res);
1035	            Resource::clean(&mut res);
1036	        }
1037	        None => tracing::error!("{} Undeclare unknown resource!", face),
1038	    }
1039	
1040	    drop(wtables);
1041	}
