1051	        match rtables
1052	            .data
1053	            .get_mapping(face, &expr.scope, expr.mapping)
1054	            .cloned()
1055	        {
1056	            Some(mut prefix) => {
1057	                let res = Resource::get_resource(&prefix, &expr.suffix);
1058	                let (res, wtables) = if res.as_ref().map(|r| r.ctx.is_some()).unwrap_or(false) {
1059	                    drop(rtables);
