1061	                    (res.unwrap(), wtables)
1062	                } else {
1063	                    let mut fullexpr = prefix.expr().to_string();
1064	                    fullexpr.push_str(expr.suffix.as_ref());
1065	                    let mut matches = keyexpr::new(fullexpr.as_str())
1066	                        .map(|ke| Resource::get_matches(&rtables.data, ke))
1067	                        .unwrap_or_default();
1068	                    drop(rtables);
1069	                    let mut wtables = zwrite!(tables.tables);
1070	                    let mut res =
1071	                        Resource::make_resource(&mut wtables, &mut prefix, expr.suffix.as_ref());
1072	                    matches.push(Arc::downgrade(&res));
1073	                    Resource::match_resource(&wtables.data, &mut res, matches);
1074	                    (res, wtables)
1075	                };
1076	                get_mut_unchecked(face)
1077	                    .remote_key_interests
1078	                    .insert(id, Some(res));
