72	    pub(crate) fn declare_queryable(
73	        &self,
74	        id: QueryableId,
75	        expr: &WireExpr,
76	        qabl_info: &QueryableInfoType,
77	        node_id: NodeId,
78	        send_declare: &mut SendDeclare,
79	    ) {
80	        self.with_mapped_expr(expr, |tables, mut res| {
81	            let region = self.state.region;
82	
83	            let mut ctx = DispatcherContext {
84	                tables_lock: &self.tables,
85	                tables: &mut tables.data,
86	                src_face: &mut self.state.clone(),
87	                send_declare,
88	            };
89	
90	            tables.hats[region].register_queryable(
91	                ctx.reborrow(),
92	                id,
93	                res.clone(),
94	                node_id,
95	                qabl_info,
96	            );
97	
98	            tables.hats[region].disable_query_routes(&mut res);
99	
100	            for dst in tables.hats.regions().collect_vec() {
101	                let other_info = tables
102	                    .hats
103	                    .values()
104	                    .filter(|hat| hat.region() != dst)
105	                    .flat_map(|hat| hat.remote_queryables_of(ctx.tables, &res))
106	                    .reduce(merge_qabl_infos);
107	
108	                tables.hats[dst].propagate_queryable(ctx.reborrow(), res.clone(), other_info);
109	            }
110	        });
111	    }
