119	    pub(crate) fn undeclare_queryable(
120	        &self,
121	        id: QueryableId,
122	        expr: &WireExpr,
123	        node_id: NodeId,
124	        send_declare: &mut SendDeclare,
125	    ) {
126	        self.with_mapped_nullable_expr(expr, /* make_if_unknown */ false, |tables, res| {
127	            let region = self.state.region;
128	
129	            let mut ctx = DispatcherContext {
130	                tables_lock: &self.tables,
131	                tables: &mut tables.data,
132	                src_face: &mut self.state.clone(),
133	                send_declare,
134	            };
135	
136	            match tables.hats[region].unregister_queryable(ctx.reborrow(), id, res.clone(), node_id)
137	            {
138	                UnregisterEntityResult::Noop => {} // ¯\_(ツ)_/¯
139	                UnregisterEntityResult::InfoUpdate { mut res } => {
140	                    tables.hats[region].disable_query_routes(&mut res);
141	
142	                    for dst in tables.hats.regions().collect_vec() {
143	                        let other_info = tables
144	                            .hats
145	                            .values()
146	                            .filter(|hat| hat.region() != dst)
147	                            .filter_map(|hat| hat.remote_queryables_of(ctx.tables, &res))
148	                            .reduce(merge_qabl_infos);
149	
150	                        tables.hats[dst].propagate_queryable(
151	                            ctx.reborrow(),
152	                            res.clone(),
153	                            other_info,
154	                        );
155	                    }
156	                }
157	                UnregisterEntityResult::LastUnregistered { mut res } => {
158	                    tables.hats[region].disable_query_routes(&mut res);
159	
160	                    let remainder = tables
161	                        .hats
162	                        .values()
163	                        .filter_map(|hat| {
164	                            (hat.region() != region)
165	                                .then(|| hat.remote_queryables_of(ctx.tables, &res))
166	                                .flatten()
167	                                .map(|info| (hat.region(), info))
168	                        })
169	                        .collect_vec();
170	
171	                    match &*remainder {
172	                        [] => {
173	                            for hat in tables.hats.values_mut() {
174	                                hat.unpropagate_queryable(ctx.reborrow(), res.clone());
175	                            }
176	                            Resource::clean(&mut res);
177	                        }
178	                        [(last_owner, _)] => tables.hats[last_owner]
179	                            .unpropagate_last_non_owned_queryable(ctx, res.clone()),
180	                        _ => {
181	                            for hat in tables.hats.values_mut() {
182	                                let other_info = remainder
183	                                    .iter()
184	                                    .filter_map(|(region, info)| {
185	                                        (region != &hat.region()).then_some(*info)
186	                                    })
187	                                    .reduce(merge_qabl_infos);
188	
189	                                hat.propagate_queryable(ctx.reborrow(), res.clone(), other_info);
190	                            }
191	                        }
192	                    }
193	                }
194	            }
195	        });
196	    }
