198	    pub fn route_query(&self, msg: &mut Request) {
199	        let rtables = zread!(self.tables.tables);
200	        match rtables
201	            .data
202	            .get_mapping(&self.state, &msg.wire_expr.scope, msg.wire_expr.mapping)
203	        {
204	            Some(prefix) => {
205	                tracing::debug!(
206	                    "{}:{} Route query for res {}{}",
207	                    self.state,
208	                    msg.id,
209	                    prefix.expr(),
210	                    msg.wire_expr.suffix.as_ref(),
211	                );
212	                let prefix = prefix.clone();
213	                let expr = RoutingExpr::new(&prefix, msg.wire_expr.suffix.as_ref());
214	
215	                #[cfg(feature = "stats")]
216	                let payload_observer =
217	                    super::stats::PayloadObserver::new(msg, Some(&expr), &rtables);
218	                #[cfg(feature = "stats")]
219	                payload_observer.observe_payload(zenoh_stats::Rx, &self.state, msg);
220	
221	                let mut builder = RouteBuilder::<QueryDirection>::new();
222	
223	                let queries_lock = zwrite!(self.tables.queries_lock);
224	
225	                let query = Arc::new(Query {
226	                    src_face: self.state.clone(),
227	                    src_qid: msg.id,
228	                    src_qos: msg.ext_qos,
229	                });
230	
231	                let src_face = &self.state;
232	
233	                if !rtables.ingress_filter(src_face) {
234	                    return;
235	                }
236	
237	                for dst in rtables.hats.regions() {
238	                    let qabls =
239	                        get_query_route(&rtables, src_face, &expr, msg.ext_nodeid.node_id, &dst);
240	
241	                    let filter = {
242	                        let src_zid = rtables.hats[src_face.region]
243	                            .remote_node_id_to_zid(src_face, msg.ext_nodeid.node_id);
244	                        let tables = &rtables;
245	
246	                        move |q: &QueryTargetQabl| {
247	                            InterRegionFilter {
248	                                src: &src_face.region,
249	                                dst: &q.region,
250	                                src_zid: src_zid.as_ref(),
251	                                fwd_zid: Some(&self.state.zid),
252	                                dst_zid: Some(&q.dir.dst_face.zid),
253	                            }
254	                            .resolve(tables)
255	                                && tables.egress_filter(src_face, &q.dir.dst_face)
256	                        }
257	                    };
258	
259	                    self.compute_final_route(msg.ext_target, &mut builder, &query, &qabls, filter);
260	                }
261	
262	                // NOTE: it's important to drop the `Arc<Query>` object immediately otherwise
263	                // a ResponseFinal from a local queryable won't finalize the query,
264	                // this is because `Arc::strong_count(&query)` would always be > 1.
265	                drop(query);
266	
267	                let timeout = msg
268	                    .ext_timeout
269	                    .unwrap_or(rtables.data.queries_default_timeout);
270	
271	                drop(queries_lock);
272	                drop(rtables);
273	
274	                let dirs = builder.build();
275	
276	                tracing::trace!(?dirs);
277	
278	                if dirs.is_empty() {
279	                    tracing::debug!(
280	                        "{}:{} Send final reply (no matching queryables or not master)",
281	                        self.state,
282	                        msg.id
283	                    );
284	                    self.state
285	                        .primitives
286	                        .clone()
287	                        .send_response_final(&mut ResponseFinal {
288	                            rid: msg.id,
289	                            ext_qos: msg.ext_qos,
290	                            ext_tstamp: None,
291	                        });
292	                } else {
293	                    for QueryDirection { dir, rid } in dirs.into_iter() {
294	                        QueryCleanup::spawn_query_clean_up_task(
295	                            &dir.dst_face,
296	                            &self.tables,
297	                            rid,
298	                            msg.ext_qos,
299	                            timeout,
300	                        );
301	
302	                        tracing::trace!(
303	                            "{}:{} Propagate query to {}:{}",
304	                            self.state,
305	                            msg.id,
306	                            dir.dst_face,
307	                            rid
308	                        );
309	
310	                        let msg = &mut Request {
311	                            id: rid,
312	                            wire_expr: dir.wire_expr,
313	                            ext_qos: msg.ext_qos,
314	                            ext_tstamp: msg.ext_tstamp,
315	                            ext_nodeid: request::ext::NodeIdType {
316	                                node_id: dir.node_id,
317	                            },
318	                            ext_target: msg.ext_target,
319	                            ext_budget: msg.ext_budget,
320	                            ext_timeout: msg.ext_timeout,
321	                            payload: msg.payload.clone(),
322	                        };
323	
324	                        if dir.dst_face.primitives.send_request(msg) {
325	                            #[cfg(feature = "stats")]
326	                            payload_observer.observe_payload(zenoh_stats::Tx, &dir.dst_face, msg);
327	                        }
328	                    }
329	                }
330	            }
331	            None => {
332	                tracing::error!(
333	                    "{}:{} Route query with unknown scope {}! Send final reply.",
334	                    self.state,
335	                    msg.id,
336	                    msg.wire_expr.scope,
337	                );
338	                drop(rtables);
339	                self.state
340	                    .primitives
341	                    .clone()
342	                    .send_response_final(&mut ResponseFinal {
343	                        rid: msg.id,
344	                        ext_qos: msg.ext_qos,
345	                        ext_tstamp: None,
346	                    });
347	            }
348	        }
349	    }
