351	    #[allow(clippy::incompatible_msrv)]
352	    fn compute_final_route(
353	        &self,
354	        target: QueryTarget,
355	        route: &mut RouteBuilder<QueryDirection>,
356	        query: &Arc<Query>,
357	        qabls: &Arc<QueryTargetQablSet>,
358	        filter: impl Fn(&QueryTargetQabl) -> bool,
359	    ) {
360	        match target {
361	            QueryTarget::All => {
362	                for qabl in qabls.iter().filter(|q| filter(q)) {
363	                    route.insert(qabl.dir.dst_face.id, || {
364	                        let mut dir = qabl.dir.clone();
365	                        let rid = insert_pending_query(&mut dir.dst_face, query.clone());
366	                        tracing::debug!(dst = %dir.dst_face, dst.target = "all");
367	                        QueryDirection { dir, rid }
368	                    });
369	                }
370	            }
371	            QueryTarget::AllComplete => {
372	                for qabl in qabls
373	                    .iter()
374	                    .filter(|q| q.info.is_none_or(|info| info.complete) && filter(q))
375	                {
376	                    route.insert(qabl.dir.dst_face.id, || {
377	                        let mut dir = qabl.dir.clone();
378	                        let rid = insert_pending_query(&mut dir.dst_face, query.clone());
379	                        tracing::debug!(dst = %dir.dst_face, dst.target = "all-complete");
380	                        QueryDirection { dir, rid }
381	                    });
382	                }
383	            }
384	            QueryTarget::BestMatching => {
385	                if let Some(qabl) = qabls
386	                    .iter()
387	                    .find(|q| q.info.is_some_and(|info| info.complete) && filter(q))
388	                {
389	                    route.insert(qabl.dir.dst_face.id, || {
390	                        let mut dir = qabl.dir.clone();
391	                        let rid = insert_pending_query(&mut dir.dst_face, query.clone());
392	                        tracing::debug!(dst = %dir.dst_face, dst.target = "best-matching");
393	                        QueryDirection { dir, rid }
394	                    });
395	                } else {
396	                    self.compute_final_route(QueryTarget::All, route, query, qabls, filter)
397	                }
398	            }
399	        }
400	    }
401	}
