403	#[inline]
404	fn insert_pending_query(outface: &mut Arc<FaceState>, query: Arc<Query>) -> RequestId {
405	    let outface_mut = get_mut_unchecked(outface);
406	    // This `wrapping_add` is kind of "safe" because it would require an incredible amount
407	    // of parallel running queries to conflict a currently used id.
408	    // However, query ids are encoded with varint algorithm, so an incremental id isn't a
409	    // good match, and there is still room for optimization.
410	    outface_mut.next_qid = outface_mut.next_qid.wrapping_add(1);
411	    let qid = outface_mut.next_qid;
412	    outface_mut.pending_queries.insert(
413	        qid,
414	        (query, outface_mut.task_controller.get_cancellation_token()),
415	    );
416	    qid
417	}
