419	#[derive(Clone)]
420	struct QueryCleanup {
421	    tables: Arc<TablesLock>,
422	    face: Weak<FaceState>,
423	    qid: RequestId,
424	    qos: response::ext::QoSType,
425	    timeout: Duration,
426	}
427	
428	impl QueryCleanup {
429	    pub fn spawn_query_clean_up_task(
430	        face: &Arc<FaceState>,
431	        tables_ref: &Arc<TablesLock>,
432	        qid: u32,
433	        qos: response::ext::QoSType,
434	        timeout: Duration,
435	    ) {
436	        let mut cleanup = QueryCleanup {
437	            tables: tables_ref.clone(),
438	            face: Arc::downgrade(face),
439	            qid,
440	            qos,
441	            timeout,
442	        };
443	        let queries_lock = zread!(tables_ref.queries_lock);
444	        if let Some((_, cancellation_token)) = face.pending_queries.get(&qid) {
445	            let c_cancellation_token = cancellation_token.clone();
446	            drop(queries_lock);
447	            face.task_controller
448	                .spawn_with_rt(zenoh_runtime::ZRuntime::Net, async move {
449	                    tokio::select! {
450	                        _ = tokio::time::sleep(timeout) => { cleanup.run().await }
451	                        _ = c_cancellation_token.cancelled() => {}
452	                    }
453	                });
454	        }
455	    }
456	}
