458	#[async_trait]
459	impl Timed for QueryCleanup {
460	    async fn run(&mut self) {
461	        if let Some(mut face) = self.face.upgrade() {
462	            let ext_respid = Some(response::ext::ResponderIdType {
463	                zid: face.zid,
464	                eid: 0,
465	            });
466	            route_send_response(
467	                &self.tables,
468	                &mut face,
469	                &mut Response {
470	                    rid: self.qid,
471	                    wire_expr: WireExpr::empty(),
472	                    payload: ResponseBody::Err(zenoh::Err {
473	                        encoding: Encoding::default(),
474	                        ext_sinfo: None,
475	                        #[cfg(feature = "shared-memory")]
476	                        ext_shm: None,
477	                        ext_unknown: vec![],
478	                        payload: ZBuf::from("Timeout".as_bytes().to_vec()),
479	                    }),
480	                    ext_qos: self.qos,
481	                    ext_tstamp: None,
482	                    ext_respid,
483	                },
484	            );
485	            let queries_lock = zwrite!(self.tables.queries_lock);
486	            if let Some(query) = get_mut_unchecked(&mut face)
487	                .pending_queries
488	                .remove(&self.qid)
489	            {
490	                drop(queries_lock);
491	                tracing::warn!(
492	                    "{}:{} Didn't receive final reply for query {}:{}: Timeout({:#?})!",
493	                    face,
494	                    self.qid,
495	                    query.0.src_face,
496	                    query.0.src_qid,
497	                    self.timeout,
498	                );
499	                finalize_pending_query(query);
500	            }
501	        }
502	    }
503	}
