505	#[inline]
506	fn get_query_route(
507	    tables: &Tables,
508	    src_face: &FaceState,
509	    expr: &RoutingExpr,
510	    routing_context: NodeId,
511	    region: &Region,
512	) -> Arc<QueryTargetQablSet> {
513	    let node_id = tables.hats[region].map_routing_context(&tables.data, src_face, routing_context);
514	    let compute_route =
515	        || tables.hats[region].compute_query_route(&tables.data, &src_face.region, expr, node_id);
516	    if let Some(query_routes) = expr
517	        .resource()
518	        .as_ref()
519	        .and_then(|res| res.ctx.as_ref())
520	        .map(|ctx| &ctx.hats[region].query_routes)
521	    {
522	        return get_or_set_route(
523	            query_routes,
524	            tables.data.hats[region].routes_version,
525	            &src_face.region,
526	            node_id,
527	            compute_route,
528	        );
529	    }
530	    compute_route()
531	}
