533	pub(crate) fn route_send_response(
534	    tables_ref: &Arc<TablesLock>,
535	    face: &mut Arc<FaceState>,
536	    msg: &mut Response,
537	) {
538	    let tables = zread!(tables_ref.tables);
539	    match tables
540	        .data
541	        .get_mapping(face, &msg.wire_expr.scope, msg.wire_expr.mapping)
542	    {
543	        Some(prefix) => {
544	            let expr = msg
545	                .wire_expr
546	                .is_empty() // account for empty wire expression in ReplyErr messages
547	                .not()
548	                .then(|| RoutingExpr::new(prefix, msg.wire_expr.suffix.as_ref()));
549	            #[cfg(feature = "stats")]
550	            let payload_observer = super::stats::PayloadObserver::new(msg, expr.as_ref(), &tables);
551	            #[cfg(feature = "stats")]
552	            payload_observer.observe_payload(zenoh_stats::Rx, face, msg);
553	            let queries_lock = zread!(tables_ref.queries_lock);
554	            match face
555	                .pending_queries
556	                .get(&msg.rid)
557	                .map(|(q, _)| q.as_ref().clone())
558	            {
559	                Some(query) => {
560	                    if let Some(expr) = expr {
561	                        // TODO: consider to optimize keyexpr for 2.0 ?
562	                        // Doing it now will break wire compatibility
563	                        // msg.wire_expr = expr.get_best_key(src_face.id).to_owned();
564	                        match expr.key_expr() {
565	                            Some(key_expr) => {
566	                                msg.wire_expr =
567	                                    WireExpr::empty().with_suffix(key_expr.as_str()).to_owned();
568	                            }
569	                            None => {
570	                                tracing::error!("{}:{} Route reply: wire expr {} does not map to a valid key expression!", face, msg.rid, msg.wire_expr);
571	                                return;
572	                            }
573	                        }
574	                    }
575	                    tracing::trace!(
576	                        "{}:{} Route reply for query {}:{} ({})",
577	                        face,
578	                        msg.rid,
579	                        query.src_face,
580	                        query.src_qid,
581	                        msg.wire_expr.suffix.as_ref()
582	                    );
583	                    drop(tables);
584	                    drop(queries_lock);
585	
586	                    msg.rid = query.src_qid;
587	                    msg.ext_qos = query.src_qos;
588	                    if query.src_face.primitives.send_response(msg) {
589	                        #[cfg(feature = "stats")]
590	                        payload_observer.observe_payload(zenoh_stats::Tx, &query.src_face, msg);
591	                    }
592	                }
593	                None => tracing::warn!("{}:{} Route reply: Query not found!", face, msg.rid),
594	            }
595	        }
596	        None => {
597	            tracing::error!(
598	                "{} Routing reply {} for unknown scope {}",
599	                face,
600	                msg.rid,
601	                msg.wire_expr.scope
602	            )
603	        }
604	    }
605	}
