607	pub(crate) fn route_send_response_final(
608	    tables_ref: &Arc<TablesLock>,
609	    face: &mut Arc<FaceState>,
610	    qid: RequestId,
611	) {
612	    let queries_lock = zwrite!(tables_ref.queries_lock);
613	    match get_mut_unchecked(face).pending_queries.remove(&qid) {
614	        Some(query) => {
615	            drop(queries_lock);
616	            tracing::debug!(
617	                "{}:{} Received final reply for query {}:{} strong_count={}",
618	                face,
619	                qid,
620	                query.0.src_face,
621	                query.0.src_qid,
622	                Arc::strong_count(&query.0)
623	            );
624	            finalize_pending_query(query);
625	        }
626	        None => tracing::warn!("{}:{} Route final reply: Query not found!", face, qid),
627	    }
628	}
