630	pub(crate) fn finalize_pending_queries(tables_ref: &TablesLock, face: &mut Arc<FaceState>) {
631	    let queries_lock = zwrite!(tables_ref.queries_lock);
632	    for (_, query) in get_mut_unchecked(face).pending_queries.drain() {
633	        finalize_pending_query(query);
634	    }
635	    drop(queries_lock);
636	}
