638	pub(crate) fn finalize_pending_query(query: (Arc<Query>, CancellationToken)) {
639	    let (query, cancellation_token) = query;
640	    cancellation_token.cancel();
641	    if let Some(query) = Arc::into_inner(query) {
642	        tracing::debug!("{}:{} Propagate final reply", query.src_face, query.src_qid);
643	        query
644	            .src_face
645	            .primitives
646	            .clone()
647	            .send_response_final(&mut ResponseFinal {
648	                rid: query.src_qid,
649	                ext_qos: query.src_qos,
650	                ext_tstamp: None,
651	            });
652	    }
653	}
