655	pub(crate) fn merge_qabl_infos(
656	    mut this: QueryableInfoType,
657	    info: QueryableInfoType,
658	) -> QueryableInfoType {
659	    this.distance = match (this.complete, info.complete) {
660	        (true, true) | (false, false) => std::cmp::min(this.distance, info.distance),
661	        (true, false) => this.distance,
662	        (false, true) => info.distance,
663	    };
664	    this.complete = this.complete || info.complete;
665	    this
666	}
