668	impl LocalResourceInfoTrait<Arc<Resource>> for QueryableInfoType {
669	    fn aggregate(
670	        self_val: Option<Self>,
671	        self_res: &Arc<Resource>,
672	        other_val: &Self,
673	        other_res: &Arc<Resource>,
674	    ) -> Self {
675	        // shortcut to avoid checking inclusion of ke, since we only care about completeness in aggregates and can ignore distance
676	        if let Some(val) = self_val {
677	            if val.complete == other_val.complete {
678	                return val;
679	            }
680	        }
681	
682	        let other_complete = if other_val.complete {
683	            if let (Some(self_ke), Some(other_ke)) = (self_res.keyexpr(), other_res.keyexpr()) {
684	                other_ke.includes(self_ke)
685	            } else {
686	                false
687	            }
688	        } else {
689	            false
690	        };
691	        let mut other_val = *other_val;
692	        other_val.complete = other_complete;
693	
694	        if let Some(val) = self_val {
695	            merge_qabl_infos(val, other_val)
696	        } else {
697	            other_val
698	        }
699	    }
700	}
701	
702	pub(crate) type LocalQueryables = LocalResources<QueryableId, Arc<Resource>, QueryableInfoType>;
