164	                        ext_qos: declare::ext::QoSType::DECLARE,
165	                        ext_tstamp: None,
166	                        ext_nodeid: declare::ext::NodeIdType::DEFAULT,
167	                        body: DeclareBody::UndeclareSubscriber(UndeclareSubscriber {
168	                            id: update.id,
169	                            ext_wire_expr: WireExprType::null(),
170	                        }),
171	                    },
172	                    update.resource.expr().to_string(),
173	                ),
174	            );
175	        }
176	    }
