193	    fn sourced_publishers(&self, tables: &TablesData) -> HashMap<Arc<Resource>, Sources> {
194	        let mut result = HashMap::new();
195	        for face in self.owned_faces(tables) {
196	            for res in self
197	                .face_hat(face)
198	                .remote_interests
199	                .values()
200	                .filter_map(|i| {
201	                    if i.options.subscribers() {
202	                        i.res.as_ref()
203	                    } else {
204	                        None
205	                    }
206	                })
207	            {
208	                result
