49	
50	impl Hat {
51	    #[tracing::instrument(level = "debug", skip_all, ret)]
52	    pub(super) fn repropagate_interests(
53	        &self,
54	        ctx: DispatcherContext,
55	        other_hats: &RegionMap<&dyn HatTrait>,
56	    ) {
57	        if ctx.src_face.remote_bound.is_north() {
58	            return;
59	        }
60	
61	        for RemoteInterest { res, options, .. } in other_hats
62	            .values()
63	            .filter(|hat| hat.region().bound().is_south())
64	            .flat_map(|hat| hat.remote_interests(ctx.tables))
65	        {
66	            let id = self
67	                .face_hat(ctx.src_face)
68	                .next_id
69	                .fetch_add(1, Ordering::SeqCst);
70	            let face_id = ctx.src_face.id;
71	            get_mut_unchecked(ctx.src_face)
72	                .local_interests
73	                .insert(id, InterestState::new(face_id, options, res.clone(), false));
74	            let wire_expr = res
75	                .as_ref()
76	                .map(|res| Resource::decl_key(res, ctx.src_face));
77	            ctx.src_face
78	                .primitives
79	                .send_interest(RoutingContext::with_expr(
80	                    &mut Interest {
81	                        id,
82	                        mode: InterestMode::CurrentFuture,
83	                        options,
84	                        wire_expr,
85	                        ext_qos: interest::ext::QoSType::INTEREST,
86	                        ext_tstamp: None,
87	                        ext_nodeid: interest::ext::NodeIdType::DEFAULT,
88	                    },
89	                    res.as_ref()
90	                        .map(|res| res.expr().to_string())
91	                        .unwrap_or_default(),
92	                ));
93	        }
94	    }
95	}
96	
97	impl HatInterestTrait for Hat {
98	    #[allow(clippy::incompatible_msrv)]
99	    #[tracing::instrument(level = "debug", skip(ctx, msg), fields(%src), ret)]
100	    fn route_interest(
101	        &mut self,
102	        ctx: DispatcherContext,
103	        msg: &Interest,
104	        res: Option<Arc<Resource>>,
105	        src: &Remote,
106	    ) -> RouteInterestResult {
107	        use RouteInterestResult::*;
108	
109	        debug_assert_ne!(msg.mode, InterestMode::Final);
110	        debug_assert!(self.region().bound().is_north());
111	        debug_assert_implies!(
112	            ctx.src_face.region.bound().is_north(),
113	            ctx.src_face.whatami.is_peer()
114	        );
115	        debug_assert_implies!(msg.mode == InterestMode::Current, msg.options.tokens());
116	
117	        if ctx.src_face.region.bound().is_north() {
118	            return ResolvedCurrentInterest;
119	        }
120	
121	        // NOTE(regions): `Current` (and not `CurrentFuture`) interests are stateless, i.e. gateways
122	        // don't register inbound/outbound token propagation. For this reason, we pick at most one
123	        // destination for `Current` interests; otherwise we would wind up with duplicate tokens.
124	        let dsts = if msg.mode == InterestMode::Current {
125	            // NOTE(regions): we don't send current-future interest to peers with unfinalized
126	            // initial interests. After finalization, we will be notified with potential tokens
127	            // and propagate them as future tokens.
128	            self.owned_faces(ctx.tables)
129	                .filter(|p| {
130	                    p.id != ctx.src_face.id
131	                        && p.remote_bound.is_north()
132	                        && !initial_interest(p).is_none_or(|i| i.finalized)
133	                })
134	                .chain(
135	                    self.owned_faces(ctx.tables)
136	                        .find(|f| f.remote_bound.is_south()),
137	                )
138	                .cloned()
139	                .collect_vec()
140	            // FIXME(regions): we may get duplicate tokens when sending to one gateway _and_ (at
141	            // least) one peer with unfinalized initial interest.
142	        } else {
143	            self.owned_faces(ctx.tables)
144	                .filter(|f| f.remote_bound.is_south())
145	                .cloned()
146	                .collect_vec()
147	        };
148	
149	        let interest = Arc::new(CurrentInterest {
150	            src: src.clone(),
151	            src_region: ctx.src_face.region,
152	            src_interest_id: msg.id,
153	            mode: msg.mode,
154	        });
155	
156	        for mut dst in dsts {
157	            let id = self.face_hat(&dst).next_id.fetch_add(1, Ordering::SeqCst);
158	
159	            if msg.mode.is_future() {
160	                let dst_id = dst.id;
161	                let is_finalized = msg.mode == InterestMode::Future;
162	                get_mut_unchecked(&mut dst).local_interests.insert(
163	                    id,
164	                    InterestState::new(dst_id, msg.options, res.clone(), is_finalized),
165	                );
166	            }
167	
168	            if msg.mode.is_current() {
169	                let dst_face_mut = get_mut_unchecked(&mut dst);
170	                let cancellation_token = dst_face_mut.task_controller.get_cancellation_token();
171	                let rejection_token = dst_face_mut.task_controller.get_cancellation_token();
172	                dst_face_mut.pending_current_interests.insert(
173	                    id,
174	                    PendingCurrentInterest {
175	                        interest: interest.clone(),
176	                        cancellation_token,
177	                        rejection_token,
178	                    },
179	                );
180	                CurrentInterestCleanup::spawn_interest_clean_up_task(
181	                    &dst,
182	                    ctx.tables_lock,
183	                    id,
184	                    ctx.tables.interests_timeout,
185	                );
186	            }
187	            let wire_expr = res.as_ref().map(|res| Resource::decl_key(res, &mut dst));
188	            dst.primitives.send_interest(RoutingContext::with_expr(
189	                &mut Interest {
190	                    id,
191	                    mode: msg.mode,
192	                    options: msg.options,
193	                    wire_expr,
194	                    ext_qos: interest::ext::QoSType::INTEREST,
195	                    ext_tstamp: None,
196	                    ext_nodeid: interest::ext::NodeIdType::DEFAULT,
197	                },
198	                res.as_ref()
199	                    .map(|res| res.expr().to_string())
200	                    .unwrap_or_default(),
201	            ));
202	        }
203	
204	        if msg.mode.is_current() && Arc::into_inner(interest).is_some() {
205	            ResolvedCurrentInterest
206	        } else {
207	            Noop
208	        }
209	    }
