211	    #[tracing::instrument(level = "debug", skip(ctx, _msg), ret)]
212	    fn route_interest_final(
213	        &mut self,
214	        ctx: DispatcherContext,
215	        _msg: &Interest,
216	        remote_interest: &RemoteInterest,
217	    ) {
218	        debug_assert!(self.region().bound().is_north());
219	        debug_assert!(ctx.src_face.region.bound().is_south());
220	
221	        if let Some(dst_face) = self
222	            .owned_faces_mut(ctx.tables)
223	            .find(|f| f.remote_bound.is_south())
224	            .map(get_mut_unchecked)
225	        {
226	            dst_face.local_interests.retain(|id, local_interest| {
227	                if local_interest == remote_interest {
228	                    dst_face.primitives.send_interest(RoutingContext::with_expr(
229	                        &mut Interest {
230	                            id: *id,
231	                            mode: InterestMode::Final,
232	                            // NOTE: InterestMode::Final options are undefined in the current protocol specification,
233	                            // they are initialized here for internal use by local egress interceptors.
234	                            options: remote_interest.options,
235	                            wire_expr: None,
236	                            ext_qos: interest::ext::QoSType::INTEREST,
237	                            ext_tstamp: None,
238	                            ext_nodeid: interest::ext::NodeIdType::DEFAULT,
239	                        },
240	                        local_interest
241	                            .res
242	                            .as_ref()
243	                            .map(|res| res.expr().to_string())
244	                            .unwrap_or_default(),
245	                    ));
246	                    return false;
247	                }
248	                true
249	            });
250	        }
251	    }
