253	    #[tracing::instrument(level = "debug", skip(ctx), ret)]
254	    fn route_declare_final(
255	        &mut self,
256	        ctx: DispatcherContext,
257	        interest_id: InterestId,
258	    ) -> RouteCurrentDeclareResult {
259	        use RouteCurrentDeclareResult::*;
260	
261	        debug_assert!(self.owns(ctx.src_face));
262	        debug_assert!(self.region().bound().is_north());
263	        debug_assert!(ctx.src_face.region.bound().is_north());
264	        // NOTE(regions): the reverse implication doesn't hold: peer regions may exchange interests
265	        // while initial interests are unfinalized.
266	        debug_assert_implies!(
267	            interest_id == INITIAL_INTEREST_ID,
268	            ctx.src_face.remote_bound.is_north()
269	        );
270	
271	        let has_local_interest = get_mut_unchecked(ctx.src_face)
272	            .local_interests
273	            .get_mut(&interest_id)
274	            .map(|i| i.set_finalized())
275	            .is_some();
276	
277	        if interest_id == INITIAL_INTEREST_ID {
278	            if !has_local_interest {
279	                bug!("Unknown initial interest");
280	                return Noop;
281	            }
282	
283	            zenoh_runtime::ZRuntime::Net.block_in_place(async move {
284	                if let Some(runtime) = &ctx.tables.runtime {
285	                    if let Some(runtime) = runtime.upgrade() {
286	                        tracing::debug!("Terminating peer connector");
287	                        runtime
288	                            .start_conditions()
289	                            .terminate_peer_connector_zid(ctx.src_face.zid)
290	                            .await
291	                    }
292	                }
293	            });
294	
295	            Noop
296	        } else {
297	            let breadcrumb = get_mut_unchecked(ctx.src_face)
298	                .pending_current_interests
299	                .remove(&interest_id);
300	
301	            match (has_local_interest, breadcrumb) {
302	                (false, None) => {
303	                    tracing::error!("Unknown interest");
304	                    Noop
305	                }
306	                (true, None) => NoBreadcrumb,
307	                (_, Some(breadcrumb)) => {
308	                    let Some(interest) = Arc::into_inner(breadcrumb.interest) else {
309	                        // NOTE(regions): this event occurs as a result of current interests that,
310	                        // in addition to hitting the gateway, also hit peers with non-finalized
311	                        // initial interests.
312	                        tracing::debug!("Pending current interest not yet resolved");
313	                        return Noop;
314	                    };
315	
316	                    breadcrumb.cancellation_token.cancel();
317	                    Breadcrumb { interest }
318	                }
319	            }
320	        }
321	    }
322	
323	    #[tracing::instrument(level = "debug", skip(ctx), ret)]
324	    fn route_current_token(
325	        &mut self,
326	        ctx: DispatcherContext,
327	        interest_id: InterestId,
328	        _res: Arc<Resource>,
329	    ) -> RouteCurrentDeclareResult {
330	        use RouteCurrentDeclareResult::*;
331	
332	        debug_assert!(self.region().bound().is_north());
333	        debug_assert!(ctx.src_face.region.bound().is_north());
334	
335	        let has_local_interest = ctx.src_face.local_interests.contains_key(&interest_id);
336	
337	        let breadcrumb = ctx
338	            .src_face
339	            .pending_current_interests
340	            .get(&interest_id)
341	            .map(|i| i.interest.as_ref().clone());
342	
343	        match (has_local_interest, breadcrumb) {
344	            (false, None) => {
345	                tracing::error!("Unknown interest");
346	                Noop
347	            }
348	            (true, None) => NoBreadcrumb,
349	            (_, Some(interest)) => Breadcrumb { interest },
350	        }
351	    }
