353	    #[tracing::instrument(level = "debug", skip(ctx, msg), ret)]
354	    fn send_current_subscribers(
355	        &self,
356	        ctx: DispatcherContext,
357	        msg: &Interest,
358	        res: Option<Arc<Resource>>,
359	        other_matches: HashMap<Arc<Resource>, SubscriberInfo>,
360	    ) {
361	        debug_assert!(self.owns(ctx.src_face));
362	        debug_assert!(ctx.src_face.region.bound().is_south());
363	        debug_assert_ne!(msg.mode, InterestMode::Final);
364	
365	        let mut matches = other_matches.into_keys();
366	
367	        if msg.options.aggregate() {
368	            if let Some(aggregated_res) = &res {
369	                let (sub_id, sub_info) = if msg.mode.is_future() {
370	                    let face_hat_mut = self.face_hat_mut(ctx.src_face);
371	
372	                    for sub in matches {
373	                        face_hat_mut.local_subs.insert_simple_resource(
374	                            sub.clone(),
375	                            SubscriberInfo,
376	                            || face_hat_mut.next_id.fetch_add(1, Ordering::SeqCst),
377	                            HashSet::new(),
378	                        );
379	                    }
380	
381	                    face_hat_mut.local_subs.insert_aggregated_resource(
382	                        aggregated_res.clone(),
383	                        || face_hat_mut.next_id.fetch_add(1, Ordering::SeqCst),
384	                        HashSet::from_iter([msg.id]),
385	                    )
386	                } else {
387	                    (0, matches.next().map(|_| SubscriberInfo))
388	                };
389	
390	                if msg.mode.is_current() && sub_info.is_some() {
391	                    // send declare only if there is at least one resource matching the aggregate
392	                    let wire_expr = Resource::decl_key(aggregated_res, ctx.src_face);
393	                    tracing::debug!(dst = %ctx.src_face);
394	                    (ctx.send_declare)(
395	                        &ctx.src_face.primitives,
396	                        RoutingContext::with_expr(
397	                            Declare {
398	                                interest_id: Some(msg.id),
399	                                ext_qos: declare::ext::QoSType::DECLARE,
400	                                ext_tstamp: None,
401	                                ext_nodeid: declare::ext::NodeIdType::DEFAULT,
402	                                body: DeclareBody::DeclareSubscriber(DeclareSubscriber {
403	                                    id: sub_id,
404	                                    wire_expr,
405	                                }),
406	                            },
407	                            aggregated_res.expr().to_string(),
408	                        ),
409	                    );
410	                }
411	            }
412	        } else if !msg.options.aggregate() && msg.mode.is_current() {
413	            for sub in matches {
414	                let sub_id = if msg.mode.is_future() {
415	                    let face_hat_mut = self.face_hat_mut(ctx.src_face);
416	                    face_hat_mut
417	                        .local_subs
418	                        .insert_simple_resource(
419	                            sub.clone(),
420	                            SubscriberInfo,
421	                            || face_hat_mut.next_id.fetch_add(1, Ordering::SeqCst),
422	                            HashSet::from([msg.id]),
423	                        )
424	                        .0
425	                } else {
426	                    0
427	                };
428	                let wire_expr = Resource::decl_key(&sub, ctx.src_face);
429	                tracing::debug!(dst = %ctx.src_face);
430	                (ctx.send_declare)(
431	                    &ctx.src_face.primitives,
432	                    RoutingContext::with_expr(
433	                        Declare {
434	                            interest_id: Some(msg.id),
435	                            ext_qos: declare::ext::QoSType::DECLARE,
436	                            ext_tstamp: None,
437	                            ext_nodeid: declare::ext::NodeIdType::DEFAULT,
438	                            body: DeclareBody::DeclareSubscriber(DeclareSubscriber {
439	                                id: sub_id,
440	                                wire_expr,
441	                            }),
442	                        },
443	                        sub.expr().to_string(),
444	                    ),
445	                );
446	            }
447	        }
448	    }
