450	    #[tracing::instrument(level = "debug", skip(ctx, msg), ret)]
451	    fn send_current_queryables(
452	        &self,
453	        ctx: DispatcherContext,
454	        msg: &Interest,
455	        res: Option<Arc<Resource>>,
456	        other_matches: HashMap<Arc<Resource>, QueryableInfoType>,
457	    ) {
458	        debug_assert!(self.owns(ctx.src_face));
459	        debug_assert!(ctx.src_face.region.bound().is_south());
460	        debug_assert_ne!(msg.mode, InterestMode::Final);
461	
462	        // NOTE(regions): we don't propagate the regions's entities in peer-to-peer mode
463	        let matches = other_matches;
464	
465	        if msg.options.aggregate() {
466	            if let Some(aggregated_res) = &res {
467	                let (resource_id, qabl_info) = if msg.mode.is_future() {
468	                    for (qabl, qabl_info) in matches {
469	                        let face_hat_mut = self.face_hat_mut(ctx.src_face);
470	                        face_hat_mut.local_qabls.insert_simple_resource(
471	                            qabl.clone(),
472	                            qabl_info,
473	                            || face_hat_mut.next_id.fetch_add(1, Ordering::SeqCst),
474	                            HashSet::new(),
475	                        );
476	                    }
477	                    let face_hat_mut = self.face_hat_mut(ctx.src_face);
478	                    face_hat_mut.local_qabls.insert_aggregated_resource(
479	                        aggregated_res.clone(),
480	                        || face_hat_mut.next_id.fetch_add(1, Ordering::SeqCst),
481	                        HashSet::from_iter([msg.id]),
482	                    )
483	                } else {
484	                    (
485	                        QueryableId::default(),
486	                        QueryableInfoType::aggregate_many(
487	                            aggregated_res,
488	                            matches.iter().map(|(res, info)| (res, *info)),
489	                        ),
490	                    )
491	                };
492	                if let Some(ext_info) = msg.mode.is_current().then_some(qabl_info).flatten() {
493	                    // send declare only if there is at least one resource matching the aggregate
494	                    let wire_expr = Resource::decl_key(aggregated_res, ctx.src_face);
495	                    tracing::debug!(dst = %ctx.src_face);
496	                    (ctx.send_declare)(
497	                        &ctx.src_face.primitives,
498	                        RoutingContext::with_expr(
499	                            Declare {
500	                                interest_id: Some(msg.id),
501	                                ext_qos: declare::ext::QoSType::DECLARE,
502	                                ext_tstamp: None,
503	                                ext_nodeid: declare::ext::NodeIdType::DEFAULT,
504	                                body: DeclareBody::DeclareQueryable(DeclareQueryable {
505	                                    id: resource_id,
506	                                    wire_expr,
507	                                    ext_info,
508	                                }),
509	                            },
510	                            aggregated_res.expr().to_string(),
511	                        ),
512	                    );
513	                }
514	            }
515	        } else if !msg.options.aggregate() && msg.mode.is_current() {
516	            for (qabl, qabl_info) in matches {
517	                let resource_id = if msg.mode.is_future() {
518	                    let face_hat_mut = self.face_hat_mut(ctx.src_face);
519	                    face_hat_mut
520	                        .local_qabls
521	                        .insert_simple_resource(
522	                            qabl.clone(),
523	                            qabl_info,
524	                            || face_hat_mut.next_id.fetch_add(1, Ordering::SeqCst),
525	                            HashSet::from([msg.id]),
526	                        )
527	                        .0
528	                } else {
529	                    QueryableId::default()
530	                };
531	                let wire_expr = Resource::decl_key(&qabl, ctx.src_face);
532	                tracing::debug!(dst = %ctx.src_face);
533	                (ctx.send_declare)(
534	                    &ctx.src_face.primitives,
535	                    RoutingContext::with_expr(
536	                        Declare {
537	                            interest_id: Some(msg.id),
538	                            ext_qos: declare::ext::QoSType::DECLARE,
539	                            ext_tstamp: None,
540	                            ext_nodeid: declare::ext::NodeIdType::DEFAULT,
541	                            body: DeclareBody::DeclareQueryable(DeclareQueryable {
542	                                id: resource_id,
543	                                wire_expr,
544	                                ext_info: qabl_info,
545	                            }),
546	                        },
547	                        qabl.expr().to_string(),
548	                    ),
549	                );
550	            }
551	        }
552	    }
553	
554	    #[tracing::instrument(level = "debug", skip(ctx, msg), ret)]
555	    fn send_current_tokens(
556	        &self,
557	        ctx: DispatcherContext,
558	        msg: &Interest,
559	        res: Option<Arc<Resource>>,
560	        other_matches: HashSet<Arc<Resource>>,
561	    ) {
562	        debug_assert!(self.owns(ctx.src_face));
563	        debug_assert_implies!(
564	            ctx.src_face.region.bound().is_north(),
565	            ctx.src_face.whatami.is_peer()
566	        );
567	
568	        let matches = other_matches.into_iter();
569	
570	        for token in matches {
571	            let id = if msg.mode.is_future() {
572	                let face_hat = self.face_hat_mut(ctx.src_face);
573	
574	                *face_hat
575	                    .local_tokens
576	                    .entry(token.clone())
577	                    .or_insert_with(|| face_hat.next_id.fetch_add(1, Ordering::SeqCst))
578	            } else {
579	                TokenId::default()
580	            };
581	
582	            let wire_expr = Resource::decl_key(&token, ctx.src_face);
583	            tracing::debug!(dst = %ctx.src_face);
584	            (ctx.send_declare)(
585	                &ctx.src_face.primitives,
586	                RoutingContext::with_expr(
587	                    Declare {
588	                        interest_id: Some(msg.id),
589	                        ext_qos: declare::ext::QoSType::DECLARE,
590	                        ext_tstamp: None,
591	                        ext_nodeid: declare::ext::NodeIdType::DEFAULT,
592	                        body: DeclareBody::DeclareToken(DeclareToken { id, wire_expr }),
593	                    },
594	                    token.expr().to_string(),
595	                ),
596	            );
597	        }
598	    }
