600	    #[tracing::instrument(level = "debug", skip(ctx), ret)]
601	    fn propagate_current_token(
602	        &self,
603	        ctx: DispatcherContext,
604	        res: Arc<Resource>,
605	        interest: CurrentInterest,
606	    ) {
607	        debug_assert!(self.region().bound().is_south());
608	
609	        let mut dst = self.hat_remote(&interest.src).clone();
610	
611	        debug_assert!(dst.region.bound().is_south());
612	
613	        if self.face_hat(&dst).local_tokens.contains_key(&res) {
614	            tracing::debug!("Already propagated");
615	            return;
616	        }
617	
618	        let id = if interest.mode.is_future() {
619	            let id = self.face_hat(&dst).next_id.fetch_add(1, Ordering::SeqCst);
620	            self.face_hat_mut(&mut dst)
621	                .local_tokens
622	                .insert(res.clone(), id);
623	            id
624	        } else {
625	            TokenId::default()
626	        };
627	
628	        let wire_expr = Resource::decl_key(&res, &mut dst.clone());
629	        tracing::debug!(dst = %dst);
630	        (ctx.send_declare)(
631	            &dst.primitives,
632	            RoutingContext::with_expr(
633	                Declare {
634	                    interest_id: Some(interest.src_interest_id),
635	                    ext_qos: declare::ext::QoSType::DECLARE,
636	                    ext_tstamp: None,
637	                    ext_nodeid: declare::ext::NodeIdType::DEFAULT,
638	                    body: DeclareBody::DeclareToken(DeclareToken { id, wire_expr }),
639	                },
640	                res.expr().to_string(),
641	            ),
642	        );
643	    }
