645	    #[tracing::instrument(level = "debug", skip(ctx, dst), ret)]
646	    fn send_declare_final(&mut self, ctx: DispatcherContext, id: InterestId, dst: &Remote) {
647	        // I should send a DeclareFinal to the source of the current interest identified by the given IID and FID
648	
649	        let dst_face = self.hat_remote(dst);
650	
651	        tracing::debug!(dst = %dst_face);
652	        (ctx.send_declare)(
653	            &dst_face.primitives,
654	            RoutingContext::new(Declare {
655	                interest_id: Some(id),
656	                ext_qos: declare::ext::QoSType::INTEREST,
657	                ext_tstamp: None,
658	                ext_nodeid: declare::ext::NodeIdType::DEFAULT,
659	                body: DeclareBody::DeclareFinal(DeclareFinal),
660	            }),
661	        );
662	    }
663	
664	    #[tracing::instrument(level = "debug", skip(ctx, msg), ret)]
665	    fn register_interest(
666	        &mut self,
667	        ctx: DispatcherContext,
668	        msg: &Interest,
669	        res: Option<Arc<Resource>>,
670	    ) {
671	        if self
672	            .face_hat_mut(ctx.src_face)
673	            .remote_interests
674	            .contains_key(&msg.id)
675	        {
676	            tracing::error!("Interest ids cannot be re-used");
677	            return;
678	        }
679	
680	        self.face_hat_mut(ctx.src_face).remote_interests.insert(
681	            msg.id,
682	            RemoteInterest {
683	                res,
684	                options: msg.options,
685	                mode: msg.mode,
686	            },
687	        );
688	    }
689	
690	    #[tracing::instrument(level = "debug", skip(ctx, msg), fields(id = msg.id), ret)]
691	    fn unregister_interest(
692	        &mut self,
693	        ctx: DispatcherContext,
694	        msg: &Interest,
695	    ) -> Option<RemoteInterest> {
696	        debug_assert!(!self.region().bound().is_north());
697	        debug_assert!(self.owns(ctx.src_face));
698	
699	        let Some(remote_interest) = self
700	            .face_hat_mut(ctx.src_face)
701	            .remote_interests
702	            .remove(&msg.id)
703	        else {
704	            tracing::error!(id = msg.id, "Unknown remote interest");
705	            return None;
706	        };
707	
708	        if remote_interest.options.subscribers() {
709	            if remote_interest.options.aggregate() {
710	                if let Some(ires) = &remote_interest.res {
711	                    self.face_hat_mut(ctx.src_face)
712	                        .local_subs
713	                        .remove_aggregated_resource_interest(ires, msg.id);
714	                }
715	            } else {
716	                self.face_hat_mut(ctx.src_face)
717	                    .local_subs
718	                    .remove_simple_resource_interest(msg.id);
719	            }
720	        }
721	        if remote_interest.options.queryables() {
722	            if remote_interest.options.aggregate() {
723	                if let Some(ires) = &remote_interest.res {
724	                    self.face_hat_mut(ctx.src_face)
725	                        .local_qabls
726	                        .remove_aggregated_resource_interest(ires, msg.id);
727	                }
728	            } else {
729	                self.face_hat_mut(ctx.src_face)
730	                    .local_qabls
731	                    .remove_simple_resource_interest(msg.id);
732	            }
733	        }
734	
735	        self.owned_faces(ctx.tables)
736	            .all(|face| {
737	                !self
738	                    .face_hat(face)
739	                    .remote_interests
740	                    .values()
741	                    .contains(&remote_interest)
742	            })
743	            .then_some(remote_interest)
744	    }
745	
746	    #[tracing::instrument(level = "trace", skip(tables), ret)]
747	    fn remote_interests(&self, tables: &TablesData) -> HashSet<RemoteInterest> {
748	        if self.region().bound().is_north() {
749	            return HashSet::default();
750	        }
751	
752	        self.owned_faces(tables)
753	            .flat_map(|face| self.face_hat(face).remote_interests.values().cloned())
754	            .collect()
755	    }
756	}
