30	pub(crate) trait LocalResourceInfoTrait<Res: LocalResourceTrait>
31	where
32	    Self: Sized + Eq + Clone + Copy,
33	{
34	    fn aggregate(self_val: Option<Self>, self_res: &Res, other_val: &Self, other_res: &Res)
35	        -> Self;
36	
37	    fn aggregate_many<'a>(
38	        self_res: &'a Res,
39	        iter: impl Iterator<Item = (&'a Res, Self)>,
40	    ) -> Option<Self> {
41	        let mut out = None;
42	        for (res, val) in iter {
43	            out = Some(Self::aggregate(out, self_res, &val, res));
44	        }
45	        out
46	    }
47	}
