65	    AggregatedResourceData<Id, Res, Info>
66	{
67	    fn recompute_info(
68	        &self,
69	        self_res: &Res,
70	        subs: &HashMap<Res, ResourceData<Id, Res, Info>>,
71	    ) -> Option<Info> {
72	        let iter = self
73	            .aggregates
74	            .iter()
75	            .map(|r| (r, subs.get(r).unwrap().info));
76	        Info::aggregate_many(self_res, iter)
77	    }
