100	pub(crate) struct LocalResources<
101	    Id: Copy,
102	    Res: LocalResourceTrait,
103	    Info: LocalResourceInfoTrait<Res>,
104	> {
105	    simple_resources: HashMap<Res, ResourceData<Id, Res, Info>>,
106	    aggregated_resources: HashMap<Res, AggregatedResourceData<Id, Res, Info>>,
107	}
108	
109	impl<Id: Copy, Res: LocalResourceTrait, Info: LocalResourceInfoTrait<Res>>
110	    LocalResources<Id, Res, Info>
111	{
112	    pub(crate) fn new() -> Self {
113	        Self {
114	            simple_resources: HashMap::new(),
115	            aggregated_resources: HashMap::new(),
116	        }
117	    }
118	
119	    pub(crate) fn contains_simple_resource(&self, key: &Res) -> bool {
120	        self.simple_resources.contains_key(key)
121	    }
122	
123	    // Returns Id of newly inserted resource and the list of resources that were enabled/changed info by this operation
124	    pub(crate) fn insert_simple_resource<F>(
125	        &mut self,
126	        key: Res,
127	        info: Info,
128	        f_id: F,
129	        simple_interests: HashSet<InterestId>,
130	    ) -> (Id, Vec<LocalResourceInsertResult<Id, Res, Info>>)
131	    where
132	        F: FnOnce() -> Id,
133	    {
134	        let mut updated_resources = Vec::new();
135	        match self.simple_resources.entry(key.clone()) {
136	            std::collections::hash_map::Entry::Occupied(mut occupied_entry) => {
137	                {
138	                    let s_res_data = occupied_entry.get_mut();
139	                    s_res_data.simple_interest_ids.extend(simple_interests);
140	                    if !s_res_data.simple_interest_ids.is_empty() && s_res_data.info != info {
141	                        updated_resources.push(LocalResourceInsertResult {
142	                            id: s_res_data.id,
143	                            resource: key.clone(),
144	                            info,
145	                        });
146	                    }
147	                    s_res_data.info = info;
148	                };
149	                let s_res_data = self.simple_resources.get(&key).unwrap(); // reborrow as shared ref
150	
151	                for a_res in &s_res_data.aggregated_to {
152	                    if let Some(a_res_data) = self.aggregated_resources.get_mut(a_res) {
153	                        let new_info = a_res_data.recompute_info(a_res, &self.simple_resources);
154	                        if new_info != a_res_data.info {
155	                            a_res_data.info = new_info;
156	                            updated_resources.push(LocalResourceInsertResult {
157	                                id: a_res_data.id,
158	                                resource: a_res.clone(),
159	                                info: new_info.unwrap(), // aggregated resource contains at least one simple - so it is guaranteed to have an initialized info
160	                            });
161	                        }
162	                    }
163	                }
164	                (s_res_data.id, updated_resources)
165	            }
166	            std::collections::hash_map::Entry::Vacant(vacant_entry) => {
167	                let id = self
168	                    .aggregated_resources
169	                    .get(&key)
170	                    .map_or_else(f_id, |r| r.id);
171	
172	                let mut aggregated_to = HashSet::new();
173	                for (a_res, a_res_data) in &mut self.aggregated_resources {
174	                    if key.matches(a_res) {
175	                        let new_info = Info::aggregate(a_res_data.info, a_res, &info, &key);
176	                        if Some(new_info) != a_res_data.info {
177	                            a_res_data.info = Some(new_info);
178	                            updated_resources.push(LocalResourceInsertResult {
179	                                id: a_res_data.id,
180	                                resource: a_res.clone(),
181	                                info: new_info,
182	                            });
183	                        }
184	                        a_res_data.aggregates.insert(key.clone());
185	                        aggregated_to.insert(a_res.clone());
186	                    }
187	                }
188	                let inserted_res = vacant_entry.insert(ResourceData {
189	                    id,
190	                    aggregated_to,
191	                    simple_interest_ids: simple_interests,
192	                    info,
193	                });
194	                if !inserted_res.simple_interest_ids.is_empty() {
195	                    updated_resources.push(LocalResourceInsertResult {
196	                        id,
197	                        resource: key,
198	                        info,
199	                    });
200	                }
201	                (id, updated_resources)
202	            }
203	        }
204	    }
205	
206	    pub(crate) fn insert_aggregated_resource<F>(
207	        &mut self,
208	        key: Res,
209	        f_id: F,
210	        aggregated_interests: HashSet<InterestId>,
211	    ) -> (Id, Option<Info>)
212	    where
213	        F: FnOnce() -> Id,
214	    {
215	        match self.aggregated_resources.entry(key.clone()) {
216	            std::collections::hash_map::Entry::Occupied(mut occupied_entry) => {
217	                occupied_entry
218	                    .get_mut()
219	                    .aggregated_interest_ids
220	                    .extend(aggregated_interests);
221	                (occupied_entry.get().id, occupied_entry.get().info)
222	            }
223	            std::collections::hash_map::Entry::Vacant(vacant_entry) => {
224	                let mut aggregates = HashSet::new();
225	                for (s_res, s_res_data) in &mut self.simple_resources {
226	                    if s_res.matches(&key) {
227	                        s_res_data.aggregated_to.insert(key.clone());
228	                        aggregates.insert(s_res.clone());
229	                    }
230	                }
231	                let inserted_res = vacant_entry.insert(AggregatedResourceData {
232	                    id: self.simple_resources.get(&key).map_or_else(f_id, |r| r.id),
233	                    aggregates,
234	                    aggregated_interest_ids: aggregated_interests,
235	                    info: None,
236	                });
237	                inserted_res.info = inserted_res.recompute_info(&key, &self.simple_resources);
238	                (inserted_res.id, inserted_res.info)
239	            }
240	        }
241	    }
242	
243	    // Returns resources that were removed/changed info due to simple resource removal.
244	    pub(crate) fn remove_simple_resource(
245	        &mut self,
246	        key: &Res,
247	    ) -> Vec<LocalResourceRemoveResult<Id, Res, Info>> {
248	        let mut updated_resources = Vec::new();
249	        if let Some(s_res_data) = self.simple_resources.remove(key) {
250	            if !s_res_data.simple_interest_ids.is_empty() {
251	                // there was an interest for this specific resource
252	                updated_resources.push(LocalResourceRemoveResult {
253	                    id: s_res_data.id,
254	                    resource: key.clone(),
255	                    update: None,
256	                });
257	            }
258	            if !s_res_data.aggregated_to.is_empty() {
259	                for a_res in &s_res_data.aggregated_to {
260	                    let a_res_data = self.aggregated_resources.get_mut(a_res).unwrap();
261	                    a_res_data.aggregates.remove(key);
262	                    let new_info = a_res_data.recompute_info(a_res, &self.simple_resources);
263	                    if new_info != a_res_data.info {
264	                        a_res_data.info = new_info;
265	                        updated_resources.push(LocalResourceRemoveResult {
266	                            id: a_res_data.id,
267	                            resource: a_res.clone(),
268	                            update: new_info,
269	                        })
270	                    }
271	                }
272	            }
273	        }
274	        updated_resources
275	    }
276	
277	    pub(crate) fn remove_simple_resource_interest(&mut self, simple_interest: InterestId) {
278	        self.simple_resources.retain(|_, res_data| {
279	            !(res_data.simple_interest_ids.remove(&simple_interest)
280	                && res_data.simple_interest_ids.is_empty()
281	                && res_data.aggregated_to.is_empty())
282	        });
283	    }
284	
285	    pub(crate) fn remove_aggregated_resource_interest(
286	        &mut self,
287	        key: &Res,
288	        aggregated_interest: InterestId,
289	    ) -> bool {
290	        match self.aggregated_resources.entry(key.clone()) {
291	            std::collections::hash_map::Entry::Occupied(mut occupied_entry) => {
292	                if occupied_entry
293	                    .get_mut()
294	                    .aggregated_interest_ids
295	                    .remove(&aggregated_interest)
296	                {
297	                    if occupied_entry.get_mut().aggregated_interest_ids.is_empty() {
298	                        // the aggregate can be removed if there is no other interest for it
299	                        let aggregates = occupied_entry.remove().aggregates;
300	                        for s_res in aggregates {
301	                            if let std::collections::hash_map::Entry::Occupied(mut e) =
302	                                self.simple_resources.entry(s_res)
303	                            {
304	                                e.get_mut().aggregated_to.remove(key);
305	                                if e.get().simple_interest_ids.is_empty()
306	                                    && e.get().aggregated_to.is_empty()
307	                                {
308	                                    // remove simple resource if there is no interest for it, nor it is aggregated into any other one
309	                                    e.remove();
310	                                }
311	                            }
312	                        }
313	                    }
314	                    true
315	                } else {
316	                    false
317	                }
318	            }
319	            std::collections::hash_map::Entry::Vacant(_) => false,
320	        }
321	    }
322	
323	    pub(crate) fn clear(&mut self) {
324	        self.simple_resources.clear();
325	        self.aggregated_resources.clear();
326	    }
327	}
