526	        assert_eq!(out.1[0].resource, ke("test/aggregate/*"));
527	
528	        assert!(local_res.contains_simple_resource(&ke("test/aggregate/*")));
529	        let out = local_res.remove_simple_resource(&ke("test/aggregate/*"));
530	        assert_eq!(out.len(), 1);
531	        assert_eq!(out[0].id, 2);
